INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('bc6dfdcf-2c30-4e9d-80a2-19735d452b96', 'Του ναι πιο στραβά. Μαγικά με δε απλό σου επιδιορθώσεις.', '126', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e5824c1c-bce4-4ccb-a26b-72c16e4d7e6e', 'Χρονοδιαγράμματα θέλεις παίρνει συνεντεύξεις πως. Δεδομένων εκτός προγραμματιστές εντολές άλγεβρα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('06e5dade-1a13-489c-a6ed-35a429eb218f', 'Δε στις όχι γνωστή μας ο. Νέων εκτός πάρεις χρειάζονται ροή. Μέχρι μας είχαμε προσπαθούν μετρήσεις.', '129', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6e7c5555-69c8-499d-814c-308f6f992587', 'Επιστρέφουν προβληματική μπουν μάθε παίρνει. Σχεδιαστής κανείς ένας πάντα έξι φράση ότι. Έξι προγραμματιστής τα τεσσαρών.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8e6f777c-19a8-4d12-9d9c-a6417c31d557', 'Διαπιστώνεις πάντα έστειλε δούλευε. Δουλεύει πάντως ρουτίνα μέχρι φράση.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2d67d5d2-215a-4b8d-aff4-95ccfad76c57', 'Στα κόψεις κι το επιδιόρθωση. Αποφάσισε τους δεν επιδιορθώσεις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('fc123df4-9c30-42e5-8b60-dfc2ab142250', 'Κλπ σας δυστυχής κάτι προσθέσει.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3151a9dd-7278-4152-b219-7a9e98cf732f', 'Πιο συνέχεια χαρτιού έτοιμος. Εικόνες μπουν παράγοντες ανεπιθύμητη εξοργιστικά.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7d346987-82d9-4eb3-814e-3a6c4f5c49eb', 'Νέο προσλάμβανες πιο κάνεις. Ανταγωνιστής διακοπής τις επιδιορθώσεις επιδιόρθωση.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9f46cafc-c78b-4102-aba4-d6f761ff7b6a', 'Εκτός μεταγλωτίσει τον έτσι γραμμές προϊόντα σκεφτείς προγραμματιστής. Ας σημαντικό λιγότερο διορθώσεις εκτός. Και διακοπή χαρακτηριστικών γεγονός πρώτο. Με ίδιο μαγικά θα απίστευτα.', '147', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e636f937-00fd-4ccb-b5a9-69fe3363d236', 'Ρουτίνα δεν πόρτες δυστυχώς δημιουργήσεις κώδικα βασανίζουν επί.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9e558134-3449-465d-9056-df6a57b65536', 'Δε πολύ επί γέλασαν πεδία. Σας χειρότερα μαγικά για λαμβάνουν τον. Κειμένων διασφαλίζεται διαδίκτυο ανώδυνη συνάδελφος.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5c60ed60-0757-41cc-822a-37e89319bd1e', 'Σε πεδία πετάνε μεταφραστής πάντως. Ποια μεταφραστής κάτι διευθυντές. Έτοιμος εδώ πάρα σημαντικός πετάνε όχι.', '8', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('18f57d0e-aa91-432f-a228-0c77d80ecc36', 'Και κι δείξει εδώ διολισθήσεις διορθώσει. Γεύματος παραπάνω πάρα μην.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ef49d5aa-a13d-4e3f-90d7-1c3800e8df72', 'Διασφαλίζεται άπειρα αποκλειστικούς επί δημιουργια. Σαν άρα όταν διαχειριστής. Πακέτων παίξουν στέλνοντάς στο βαθμό παραδώσεις.', '150', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('bcbebfbd-0d35-43f6-a2c3-09e3ac7a5963', 'Νέου της γειτονιάς. Εφαμοργής απόλαυσε διορθώσεις οι προγραμματιστής πιο τα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f66ca7c5-4559-495f-8692-371597af507b', 'Μην καλύτερο τι. Τη σπίτι ρουτίνα τεσσαρών αναφέρονται. Σε προκαλείς εγώ σκεφτείς προϊόντα εταιρείες.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('89360d23-e44c-466e-93e9-d46c4210fa79', 'Επί νέο εφαρμογή πάντως απαρατήρητο. Έχω ας πιο μη πακέτων ειδικά για.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b87f378e-f004-4969-9bc4-8b405f8df9cb', 'Διακόψουμε ποσοστό το. Μάλλον έλεγχος μεταφραστής στα απαρατήρητο μεταγλωτιστής. Πολύ χρόνου στο ερωτήσεις περίπου δεν ερωτήσεις. Πιο θέμα αποστηθίσει έξι μέρος έστειλε.', '58', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ea84acca-32b8-443c-89d8-3a3cbc9b9383', 'Διάσημα πολύ κανένας γνωρίζουμε. Ποια θέμα ότι λέει. Γραμμές παίξουν δε εκτελέσεις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b88f4730-be3d-459b-a61f-ec7acf2a453a', 'Ελέγχου ρωτάει τρόποι σας. Χρησιμοποιούνταν βιβλίο λετπά πετάξαμε.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2ab35c90-285c-4233-bc82-9eeb8b81d6b8', 'Δύο σημεία εδώ. Περισσότερες εκτός διορθώσει ωραίο προσεκτικά να και. Που ήδη θυμάμαι στις τη έξι εργαζόμενων.', '123', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('958c2eff-f248-4f63-94aa-2fd1e0bfa345', 'Έξι μέχρι της. Έγραψες γεύματος μη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('167c1feb-f7d2-4116-8dfb-10205d4aa779', 'Παίρνουν ναι σας χαμηλός. Πήρε απόλαυσε τον διορθώσει επιστρέφουν κάτι. Περισσότερη κώδικάς μα εκτελέσεις.', '150', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b4113e19-92ea-42c9-bf57-fa8a1bfd10e1', 'Δίνοντας νιρβάνα μας όσο. Μιας ειδικά διαδίκτυο στις λίγο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4c9225d4-f979-4bc5-9469-e71db5723159', 'Συνέχεια βιβλίο έξι εδώ επί βασανίζουν. Έξι τι βγήκε στραβά ένα εργάστηκε χάος μάτσο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('81a64b16-e015-41aa-91c9-4646819931fa', 'Του ίδιο μετράει βγήκε βιβλίο. Θα για θα τελειώσει μπουν εντολές.', '10', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d5e9d84e-4b07-4387-9762-b3f2192f5b3b', 'Μας όταν διορθώσει εντολές προσοχή φίλος χαρτιού νόμιζες. Πάντως λοιπόν διορθώσεις λιγότερο παίρνουν.', '117', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a4656e00-3257-4cad-bce1-b752bf80321a', 'Επί σημεία κι δίνοντας τα. Μη ώρα κι γειτονιάς.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('43635116-5a58-4c34-98df-9a4a4b17a68b', 'Δύο προκαλείς σημαντικό εγώ μα. Θα το πακέτων περιβάλλοντος ιδιαίτερα. Σταματάς κοιτάζοντας πες τα μέρος νέου γραμμής τεκμηριώνει.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9fd73a07-79db-4786-9252-362c93f73227', 'Δίνοντας στις επεξεργασία διοικητικό υόρκη. Νέων τύπους εγώ έρθει αγοράζοντας γιαυτό δεν. Έξι συγκεντρωμένοι ίδιο ο αθόρυβες.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('bd832db0-e96b-4652-bde4-9021c08ca2d0', 'Μάλλον όσο περιεχόμενα μετράει διολισθήσεις. Μην περιβάλλον επιδιορθώσεις τους για φακέλους τοπικές. Τοπικές τι μηχανής παίρνουν.', '86', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('481a1d36-4976-44a1-a4ab-1c93a1312ae1', 'Που διάβασε πεδία κόλπα ποια. Αναφέρονται αυτήν εξαρτάται κρατήσουν των εργαλείων. Μάθε απαράδεκτη τον έχω με όταν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('30069b65-bb88-4d37-9cb6-27dcbb474deb', 'Τις το μέγιστη κοιτάζοντας περιμένουν. Όταν πακέτων γιαυτό αναγκάζονται.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9e8f56c3-ab73-46dc-a55e-4b936f002b1d', 'Απλό οι κλπ συνάδελφος. Γεγονός ημέρα όχι αντιλήφθηκαν. Αλγόριθμου πάντα ρωτάει παράγοντες ίδιο κι στο μην. Κάνεις τεκμηριώνει έτσι σημαντικό.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('89fb83c6-07f6-4e6a-8ca4-28c4589b6949', 'Άρα έτοιμος γραμμής ερώτηση δημιουργήσεις. Αναφορά άρθρων λοιπόν πάντως αποστηθίσει είχαμε μου παραγωγικής. Μέχρι όσο κώδικα δοκιμάσεις μου ένα.', '102', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('554a8414-2641-4bf5-b135-ddf34be54e3e', 'Αναγκάζονται το επεξεργασία φράση. Αν έγραψες προγραμματιστής μας απόλαυσε μια παράδειγμα.', '84', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('cb196b67-4829-4571-8cb4-fecb9c74ecf0', 'Μια νιρβάνα χαρτιού πλέον δίνοντας σωστά διάσημα. Ατόμου λες εργαζόμενων ως. Πάντα διασφαλίζεται το.', '1', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4f7b4f4b-9358-499b-b10f-8622516e5f88', 'Ήδη συγκεντρωμένοι έχω λοιπόν μη. Αν διάβασε σκεφτείς. Έλεγχος κανένας αφήσεις άλγεβρα υπηρεσία εκθέσεις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('acd7acbc-653d-4fc3-8bd7-24ddd5e1d0e6', 'Ερώτηση ως γειτονιάς μη συνεντεύξεις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('347c6937-2620-4970-acad-bdbeb6ad417a', 'Μιας πιο χάος. Του δε προσπαθήσεις συγγραφής εκείνου σπίτι άπειρα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e29d7e37-9f71-478a-b6fe-eb71a17fe3ca', 'Σας προγραμματιστής εφαρμογή ένας μέχρι για. Υόρκη αναγκάζονται απόλαυσε κι. Προσεκτικά από πρώτο κι εργοστασίου εκτελείται συνηθίζουν.', '12', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('24252e16-fa16-44f9-969a-2b024e98a196', 'Κι τα ήδη επιδιόρθωση βάζοντας αρπάζεις πεδία ότι.', '19', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4f62c0af-a264-4fc0-85a2-6083806c30a4', 'Εδώ ας πιο που εργασίας διορθώσει. Ανά πόρτες εγώ εφαμοργής.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('efc722e9-29bd-4d99-8749-9430354eb546', 'Εγώ αν εκτός τοπικές τελειώσει αποκλειστικούς παραπάνω προϊόντα. Αποκλειστικούς μέχρι δε για για έρθει.', '45', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('417ee46f-7e2a-43d2-95d6-717a11659e13', 'Δουλεύει πάρεις ζητήσεις γειτονιάς έλεγχος. Συγγραφής έτσι βρίσκονται σπίτι πάντως το ανά. Φακέλους κώδικα απαράδεκτη βρίσκονται.', '133', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5afaa686-ce72-44ba-a0c4-d14b6ed5e96c', 'Μιας πηγαίου επί τοπικές. Τους απόλαυσε άρα σημεία τρόποι χάος. Έτοιμος κανόνα συνεντεύξεις τεσσαρών.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e9e64d5d-5409-4556-bb3a-d928c493a9d6', 'Φακέλους μέχρι τοπικές φαινόμενο τη παίρνει. Γέλασαν λίγο εταιρείες. Μηχανής έξι εκείνου κώδικα όχι μη που.', '138', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e3fe85c5-df58-460e-9347-495bda220616', 'Της εκδόσεις ποσοστό χρησιμοποιώντας τεκμηριώνει. Ίδιο τα περισσότερες εργασίας γράψει. Μαγικά για κι.', '59', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1497ff6b-b996-4394-b659-60992aae1763', 'Χρονοδιαγράμματα τα παραγωγικής κι άρα χαρτιού που μέχρι. Δύο εργασίας γραμμής ήδη. Την εκτός σκεφτείς σαν αναφέρονται δυστυχώς.', '105', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a11c686d-b60c-4562-8a2f-fb0f46a5b5af', 'Περίπου περίπου προσπαθούν κανένας. Μετρήσεις επί ροή προσπαθούν τρόποι. Πετούν εφαρμογή κώδικάς της.', '99', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1b9591ba-7cf1-400c-bfca-c1477b6dbe54', 'Και περιβάλλον προσθέσει εκδόσεις. Ο να σωστά. Εδώ προγραμματιστές νόμιζες νιρβάνα διαχειριστής χρησιμοποιούσες απαραίτητο αλγόριθμου.', '61', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6d9fec31-579d-4fc2-82eb-15fb4e2e7b9e', 'Ατόμου πιο ζητήσεις. Τέλειοι συνέχεια αποφάσισε μας μου.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4610f6f8-4ffd-42cd-9b92-b186863d7aa4', 'Εκτελέσεις παράδειγμα δημιουργείς στα εφαμοργής. Απόλαυσε χρονοδιαγράμματος μια διορθώσει για περιεχόμενα. Επιδιόρθωση κι στα μια πλέον δημιουργείς.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f0778365-420d-4a91-bdb5-ca7c63629fe1', 'Τους διορθώσεις γέλασαν. Στέλνοντάς εκτός πλέον πρόσληψη νέου δεδομένων. Με περιεχόμενα γραμμές έστελνε.', '9', 'Orthopaedic');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('42fa8139-b96b-415c-abdb-a71d61b9bfcf', 'Πρώτοι παίρνει ποια ένα και τεσσαρών οι. Εργαζόμενων δεν μέρος εργαζόμενων.', '135', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3f2f808b-fb2b-44c9-bc7e-1135ba38680d', 'Δε σαν ανά κρατήσουν μάλλον προγραμματιστές. Εφαρμογή στη ένα απίστευτα.', '6', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1e12933b-ad04-4487-abc9-f88cfb14c8c1', 'Για αυτός μερικούς μεταγλωτίσει ανταγωνιστής. Πάντα πρώτης παραπάνω αποστηθίσει πρώτης πρώτοι δεν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6e340896-cb2e-404d-a721-92a25ca714cf', 'Χρονοδιαγράμματος επί από έλεγχος απαρατήρητο. Κι προκύπτουν έλεγχος.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('39326f37-31fe-42b7-95f2-333bd34c5c44', 'Χρησιμοποίησέ μη επεξεργασία και για κόψεις. Μέχρι πως ανά σχεδιαστής ερωτήσεις. Ως μια θα εκτός.', '30', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a47a2434-5891-4836-8474-36e6a7588676', 'Σε απαρατήρητο ζητήσεις προσλάμβανες λαμβάνουν εργάστηκε και. Στα ποσοστό έρθει συγκεντρωμένοι δυστυχής καλύτερο. Χρησιμοποιούνταν τρέξει συγχωνευτεί δυστυχής ποσοστό δεδομένων αρπάζεις.', '99', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d24503e2-167e-40c0-962e-c7872b70fdb2', 'Μαγικά ένα προσπαθήσεις προσλάμβανες σημεία δυστυχής δεν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ed9f4144-0492-4561-bd7d-4010f5aa8dc2', 'Μη μηχανής γραφικά χαρακτηριστικό σας ο. Χαρτιού άρα ρωτήσει προσοχή έτοιμος κοιτάζοντας.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c34b2464-d640-46e8-94c0-fa5775f54abe', 'Προσλάμβανες να και φίλος. Φακέλους χρησιμοποίησέ κι πάντως έλεγχος.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5be0cc7c-6be0-4e43-bc33-5b36d65a3c5c', 'Περισσότερη δε εργοστασίου βαθμό δεν. Ειδικά έχω μην δύο ακούσει μέσης κανένας.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8f55c995-0b8e-4c08-a9aa-72407f42064c', 'Βιβλίο μας τους παραδώσεις προγραμματιστής προσπαθούν σχεδιαστής. Παραγωγικής άλγεβρα ελέγχου επί μερικούς όταν τύπους ότι. Αντιλήφθηκαν αν νέου πλέον. Σπίτι θυμάμαι κώδικάς εκδόσεις.', '137', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('837f3094-291a-4a6a-8247-4cd84ab4abe3', 'Εδώ σίγουρος ο διορθώσεις. Περιμένουν έτσι μου σου ανά κάτι. Μέχρι και κοιτάζοντας προγραμματιστές.', '120', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a263f992-be8e-44a7-b317-397819f083cd', 'Αν λίγο ευκολότερο εργοστασίου. Λιγότερο πάντως τελειώσει σχεδιαστής τύπους πάρα της μπορούσες. Προσλάμβανες φίλος μετρήσεις χρονοδιαγράμματα.', '150', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('fcfb7c35-8584-4ac6-ba99-f63d1b382ff0', 'Κάτι κάνεις δε έστελνε διαχειριστής δημιουργια. Ότι εξακολουθεί την κόψεις τελειώσει απλό οι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('923aa08d-0894-4466-93ec-12f851fa3af8', 'Γειτονιάς ευκολότερο διολισθήσεις έξι επί τεσσαρών από. Σωστά σταματάς κώδικα άρα απλό. Διευθυντές ατόμου είχαμε έστειλε μεταγλωτιστής διακοπή διολισθήσεις.', '140', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('fcf30d18-911f-466e-9aa8-5043fcc5397e', 'Και συγχρόνως ειδικά πήρε. Εκτελέσεις πετάνε χαμηλός του είχαμε σημαντικό λετπά. Παραδοτέου διάσημα και.', '89', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6dfd77d0-9027-4e6c-8cb8-96a9c6ae6922', 'Μηχανής προϊόντα όχι εξαρτάται.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('546f753a-cba0-41ef-82f5-a0b5f2a1cacd', 'Ακούσει τον εδώ κάνε εκθέσεις. Και παραγωγικής τι ωραίο του ήδη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('792789e0-9230-4558-9c01-88976de73145', 'Δεν μηχανής απαράδεκτη αρέσει. Γέλασαν συνέχεια δεν νέο περισσότερες. Αγοράζοντας αρχεία χρειάζονται εκτός.', '131', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ed13d483-c028-4df1-b3e0-c570503fbf58', 'Υψηλότερη περιβάλλοντος δύο έστειλε αποστηθίσει. Νέου παίξουν αναγκάζονται πλέον. Αρπάζεις διακοπής ρωτήσει.', '47', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7492782a-edb2-4737-a941-316b8d44432d', 'Λαμβάνουν δε ο εργασίας εργασίας χειρότερα γραμμής. Ατόμου πλέον θέματα διολισθήσεις δύο στα και. Εκτός μαγικά γραφικά το.', '87', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('831c850b-66e6-46ce-9bce-9142ae96f069', 'Έξι στη έλεγχος έχω εκτός αποστηθίσει να. Δοκιμάσεις παραδώσεις ωραίο προκύπτουν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6c1031aa-3d61-42eb-88ee-9cd57d03a1d7', 'Απίστευτα υόρκη πρόσληψη στη τι την καταλάθος. Ναι εργαζόμενων πάρεις υποψήφιο τον τις τύπου. Απαράδεκτη ναι απλό διορθώσει αρέσει προϊόντα.', '75', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2d69f5d7-d075-42bb-a35e-811ac8091f5b', 'Δωροδοκηθούν ένας περισσότερη πλέον φαινόμενο αν. Ήδη έτοιμος απόλαυσε επί πλέον κλπ.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('de5c4c28-33a7-4237-94bb-bd7a68e964df', 'Μη επιδιορθώσεις εργαζόμενοι δημιουργείς μεταγλωτίσει συνεχώς. Εργοστασίου επεξεργασία απαρατήρητο τη. Σου ίδιο νέου πολύ άρθρων κόλπα ταξινομεί.', '146', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f1319c90-2ef1-485f-b1d5-8d9026a615c6', 'Σας ερωτήσεις σημαντικός ωραίο. Αρπάζεις κύκλο λαμβάνουν οι διάβασε. Που κόψεις νέων.', '70', 'Orthopaedic');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('208ffbfd-e9b9-472c-a2eb-e2535d0aeef3', 'Μετρήσεις ας πιο μέχρι σας σου. Γεγονός τι γραφικά δείξει ημέρα λοιπόν γραμμές.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('327b8d2b-3218-4909-8cfe-aacff7f08b56', 'Μας σου απαρατήρητο αποφάσισε ρουτίνα γεύματος σαν κανένας. Δουλεύει γειτονιάς πολύ βαθμό υποψήφιο. Εργαλείων απλό μάτσο μεταγλωτιστής δεν μας.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c72943d1-a55c-4c2c-98ab-492f207b3fe0', 'Χώρου κόλπα γράψει λαμβάνουν. Χαρτιού πάντως ως.', '46', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2c1fff25-1d59-451a-b330-ab37f1026083', 'Στα σου κανένας παραπάνω δημιουργια γράψει. Σας τύπου διοικητικό δημιουργείς προϊόντα χρόνου. Παραγωγικής προγραμματιστές πλέον πάρα εργαζόμενοι περιβάλλον πως.', '121', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('aced163b-804c-4982-b772-e3bf7605f14e', 'Χρονοδιαγράμματα και μην λέει κανένας. Περισσότερες προσλάμβανες τι κώδικάς.', '125', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('91510d67-42b5-485a-b999-877b9c86e7a5', 'Ποια μα εργαζόμενων σκεφτείς αρπάζεις. Δυστυχώς περιμένουν χρησιμοποιούσες περιβάλλοντος στη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6ea18de7-861a-489e-bca7-0aef04685ecd', 'Μάθε εδώ ορίστε γνωστή ερωτήσεις χάος. Άρα τύπους τύπους εργαλείων όχι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('edf9a169-c304-47f9-be78-d5e2e6433c3f', 'Γραμμής μεταγλωτιστής ήδη κόψεις γραμμής. Εφαρμογής ορίστε κανείς ποια μας ποσοστό έξι. Λαμβάνουν έξι χώρου κώδικα νιρβάνα σημεία σου από.', '49', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2fe2beba-cdb6-4c1c-9702-7ca77c84a555', 'Μια απίστευτα κοιτάζοντας. Διασφαλίζεται πλέον εκθέσεις λιγότερο αν.', '1', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a4d5066e-17b0-43ff-a6c8-73c23339f5fb', 'Μεταφραστής ανακλύψεις τους μα δείξει ίδιο. Προσπαθήσεις ένα άρα σου προγραμματιστής τις ζητήσεις. Άρα μιας ποια επί εργοστασίου ρωτήσει.', '7', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1ed2fe4e-0bb8-4eed-8e8a-95c627a18a73', 'Διακοπής για κόψεις αυτήν σαν εκτελέσει. Αποθηκευτικού δυστυχής πάντα από του.', '120', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('96fde4a8-1513-4667-a02d-89d340256f3d', 'Τρόποι έξι πάρα δοκιμάσεις. Πολύ ότι χάος γραφικά. Δεν αυτήν στα εδώ χρόνου άρθρων.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('330fe11f-4608-4110-9108-f424bb4ea74a', 'Επί ο συνεντεύξεις πήρε. Ευκολότερο βρίσκονται των ταξινομεί. Διάβασε κάτι ευκολότερο έγραψες ερωτήσεις δεν.', '63', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('797f4ffe-a8f2-47b4-bcbb-e068703a5126', 'Βάζοντας βάζοντας εργασίας ζητήσεις. Πρόσληψη από δημιουργείς κώδικάς.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('50e03e8d-1c13-4310-a271-f95aab6112a9', 'Τους διαδίκτυο δυστυχώς έχω χειρότερα. Πλέον αποφάσισε την εργαλείων της ωραίο.', '94', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9a391d82-dd8f-47e5-9af2-b7e43c2c3d94', 'Θυμάμαι δίνοντας διαπιστώνεις έτσι κοιτάζοντας. Διορθώσει προγραμματιστές της.', '95', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('11fde468-d518-48ef-8f64-e47023386fed', 'Από προσπαθούν κύκλο ναι διολισθήσεις βρίσκονται που. Διολισθήσεις σημαντικός πρώτο σου δε τις επενδυτής.', '6', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ae18d7a4-fbc1-4126-b974-6f5349911f58', 'Μέχρι προσλάμβανες όταν αυτός μάλλον. Σου φαινόμενο γειτονιάς. Λέει στη τον τον κώδικάς λετπά εσωτερικών.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9a167f27-ca43-493e-91a6-9afaae6edd35', 'Ελέγχου υόρκη στήλες δύο. Γνωστή κλπ αποφάσισε το. Προγραμματιστής ας ανακλύψεις πάρεις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d19b564f-d136-4b5c-a2ec-5776b5d87ac0', 'Μη διαπιστώνεις χρονοδιαγράμματος κρατήσουν επί μας. Συνεντεύξεις κάτι περιμένουν ημέρα περιβάλλοντος πιο.', '121', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('80378d4d-d432-43e1-b117-80cc4b829096', 'Αγοράζοντας δοκιμάσεις λαμβάνουν μέχρι κάτι εργαζόμενων εκτελείται. Σε μπορούσες αυτήν κώδικα χαρακτηριστικό.', '136', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f6d3926d-0783-428c-91ee-ee609724e3e9', 'Πάντως κάτι μιας εργαζόμενων νόμιζες εφαρμογής και. Νέα ότι γεύματος χώρου φράση λιγότερο. Τέλειοι κι τι και.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('dffc480c-3883-4c64-97ab-ac3e7f4490b7', 'Προσπαθούν των παράγοντες εργοστασίου. Νόμιζες νέο βγήκε θα μεταφραστής μετρήσεις διευθυντές.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('10986d3b-c068-469d-9d96-e1785c8c8a7f', 'Να μέρος απαραίτητο καταλάθος πιο κι συνέχεια. Εδώ πολύ τύπου μάθε ένας ίδιο κάτι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('18fad3c4-2a9a-4db6-84b6-3c8593661cd7', 'Πάντως κανόνα χρησιμοποίησέ στήλες. Απόλαυσε να διορθώσεις βαθμό.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e6c5176e-61f1-476e-bcb3-dba3db415810', 'Γραμμής τρόποι επιδιορθώσεις. Διευθυντές εγώ και τη στα προσθέσει μέρος ευκολότερο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('844c2c11-022a-4de3-87b2-a36287d6c82f', 'Διαχειριστής πάντως απίστευτα ναι. Χαμηλός ξέχασε πάντως αλγόριθμου πρώτο. Βιαστικά ήδη μεταφραστής προγραμματιστής στραβά αναγκάζονται δημιουργια εκτελέσεις.', '100', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7b0a0f38-5de7-4c37-8057-ceaed0adaf4f', 'Συγγραφείς δυστυχώς σχεδιαστής περισσότερες μέγιστη ίδιο νέων. Κάνεις μηχανής μάθε άρθρων δυστυχώς όχι πολύ. Φακέλους τους κανένας ας για σπίτι μα παραδώσεις.', '50', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('268feabe-68a2-45ac-a70c-1d2fcbf59f7e', 'Απίστευτα πάντα ερώτηση ώρα δεν σε. Λαμβάνουν ποια όχι καλύτερο περιεχόμενα για μιας. Διαχειριστής λοιπόν ρωτήσει κόψεις.', '66', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3390facb-4df2-4096-9a0d-f1f7ad81e957', 'Έτοιμος και θέλεις της υποψήφιο λετπά. Αρπάζεις ακούσει τοπικές πάντα επιστρέφουν τύπου στις γιαυτό.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('340e7c13-5a7a-4eb8-856d-cd514b11a087', 'Δύο θυμάμαι καταλάθος στα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0c5c02ed-950b-43f9-b300-e28a0f088fc7', 'Μου πάντως μετρήσεις μη βαθμό στα πρόσληψη. Συνέχεια μέσης παίρνουν θέμα άτομο.', '18', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('12e5510f-b308-4b0c-a5b1-49b02d2f6610', 'Εξοργιστικά προκύπτουν τελειώσει μη χρησιμοποιώντας. Στο έχω προσοχή άρα από διορθώσει. Προσλάμβανες απομόνωση μέχρι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d1d3ae43-e2e3-40a2-b4c0-81b7c4a2ea94', 'Γνωρίζουμε απίστευτα δεν στις ταξινομεί υποψήφιο. Βασανίζουν υπηρεσία διακόψουμε εκτελέσει. Τη προσοχή δε που.', '136', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c6aa2c9b-6ddd-4ebc-9b35-54da8c3c94e0', 'Έτσι επί περιεχόμενα σημαντικός δούλευε σημεία. Γραφικά γραμμής στέλνοντάς. Παράγοντες δε γνωρίζουμε πρώτης νέων γραφικά.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('934126bf-bf8b-47f5-843e-0de70f2b06ed', 'Απαραίτητο χρησιμοποιούσες επιδιόρθωση ξέχασε μέρος. Χειρότερα που δυστυχώς αποφάσισε κάνε. Ορίστε εκτός άτομο μας εταιρείες υποψήφιο.', '93', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('97f7d282-e5ea-431e-911c-ea6cf2a3643c', 'Χώρου κάτι για ήδη το δυστυχής πεδία μέχρι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f39dfecb-d7b1-4eeb-8084-fbc09feebe57', 'Παράδειγμα πρώτοι εκτός μιας υποψήφιο κανένας παίρνει. Κρατήσουν πάρεις με υπηρεσία αναγκάζονται. Ταξινομεί χρόνου προσοχή τύπους διακοπή ευκολότερο προσπαθήσεις.', '92', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('19bb62cb-ff24-4fa5-ba71-f316270b3a03', 'Πως σας συγγραφείς βρίσκονται ιδιαίτερα μας. Κρατάει τελειώσει κώδικάς ιδιαίτερα δούλευε χρησιμοποιούνταν κάτι.', '129', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4c41d28c-6ae7-45f0-a864-fa946200d21c', 'Εργάστηκε σαν περιμένουν σκεφτείς μαγικά.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('74fa642f-a4f8-42f5-a84b-00bda13f2dcc', 'Κι προσεκτικά εφαμοργής συνηθίζουν προσλάμβανες. Δεν ερώτηση ιδιαίτερα υψηλότερη τις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d388eaa0-6c7e-4c93-9daa-58431f3b8e87', 'Μπουν μιας ένα τον επιδιόρθωση ποια. Σπίτι για περιεχόμενα ο ανά μου.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('772e94de-2b98-4336-a2e9-4fead2c91793', 'Περισσότερη υψηλότερη ίδιο ακούσει μέσης τους διαφήμιση.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b8f40526-a4df-47ab-92b4-7ecc10c51698', 'Όσο δίνοντας τη μια. Έτσι ποσοστό έξι παραδώσεις εκδόσεις.', '115', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c0f677ff-ae02-4123-b58c-a0873ebc645a', 'Από το διακοπή. Γράψει ίδιο μάτσο νέο και τρόποι πεδία. Εξακολουθεί εργαζόμενοι του ακούσει.', '125', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d8054d5b-7021-4cba-ba3f-14fd3257bdb0', 'Έτοιμος πλέον τρέξει εδώ. Εξακολουθεί πολύ παίρνουν και των εξαρτάται. Ακούσει λιγότερο υψηλότερη και αυτήν.', '70', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4eed73e0-0145-46ce-998e-8c9345964318', 'Της τους συνεχώς εργαζόμενων παράδειγμα εκδόσεις. Άρα μάθε πάντως ώρα μπορούσες.', '108', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f7246c52-e6f2-481d-9158-0c0b00aa3a8d', 'Ανεπιθύμητη το εφαμοργής άρθρων. Και τύπου σχεδιαστής έτσι εργαζόμενοι μεταγλωτιστής δε. Ρουτίνα κρατήσουν αλγόριθμου.', '63', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('888482bb-b866-4268-be62-7185ce1ae6f1', 'Πακέτων και διάβασε. Στο ανταγωνιστής αλγόριθμου παίρνουν παίρνει έτσι.', '64', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c53dd4a3-e19a-4598-84b1-36e56198da76', 'Μάλλον πετάνε προκαλείς. Επενδυτής έξι πολύ μετρήσεις. Μη ιδιαίτερα στραβά μέρος εξακολουθεί ότι να.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9865f31c-d44e-4384-b02f-3a0ef4319c0c', 'Εκτελείται πρώτο ορίστε δυστυχής βρίσκονται παράδειγμα λοιπόν.', '8', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c9c2b4a7-4cc6-4209-8618-d679afe50fa6', 'Κώδικα διαδίκτυο άρα ποσοστό δίνοντας άλγεβρα. Έτοιμος σας όταν μέχρι της άτομο δημιουργείς όταν. Μέσης βάζοντας παραδώσεις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3fbccb44-9062-41b1-8d74-1d63bbf6e5c4', 'Χρόνου κόλπα μα διαδίκτυο. Δύο χρονοδιαγράμματα απαράδεκτη ερωτήσεις και των. Έλεγχος ένα ταξινομεί έχω επεξεργασία.', '69', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4c75824d-50b6-4b4b-b5f9-a25f4e965ad6', 'Ποια κρατάει πολύ γράψει που γραμμή την δημιουργείς. Δημιουργήσεις στη απαραίτητο τη την εκτελείται.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4bb177ec-8b94-4fbd-95e4-2d3302997353', 'Πάρεις μην χρόνου αθόρυβες χρησιμοποίησέ επιδιορθώσεις. Αποστηθίσει χαρακτηριστικών όταν ίδιο λες που. Μην προσπαθήσεις προγραμματιστής υόρκη για ρωτάει πιο.', '148', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('91704b7d-c58e-41b1-a916-2dc4bf4d4d2d', 'Προσθέσει διευθυντές διαχειριστής αναφέρονται υψηλότερη πρώτοι συνέχεια. Συγγραφείς περισσότερες νέων ας χρόνου πες άρα. Κανένας συνεντεύξεις όχι υπηρεσία.', '69', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f99df017-5480-4974-9806-2fe25b7e4d16', 'Χειρότερα ερώτηση παραπάνω επεξεργασία πετάνε. Ποια αυτός μη γραμμής ροή γεγονός υόρκη τη. Συνεντεύξεις δεν ήδη παραδώσεις εξακολουθεί πάντως.', '39', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('39730fd9-590c-4052-8126-9f1302b54250', 'Περισσότερες σίγουρος κάτι υποψήφιο έρθει που στραβά. Μιας κανένας στη.', '37', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d2626126-5e0b-4b41-96a3-bf8ad61fc49e', 'Κανείς σωστά μεταγλωτιστής κειμένων εξαρτάται. Αποφάσισε στραβά ιδιαίτερα διακόψουμε περιβάλλοντος. Ρωτήσει παραδώσεις γεύματος.', '98', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8867b299-4444-4a11-a642-8594c10974f0', 'Δε σε αποθηκευτικού. Απόλαυσε κανείς σκεφτείς τον είχαμε. Έτοιμος σας τεσσαρών βαθμό πιο γραμμές.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6a5bbcde-29a9-46a0-9512-7d9eb4e760a9', 'Ανταγωνιστής περιβάλλον χρονοδιαγράμματα στη πως. Εσωτερικών απαραίτητο όταν ποια ήδη συνηθίζουν ελέγχου. Ύψος απλό πεδία κύκλο γεύματος κάτι εκτός ένα.', '129', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('51527fe2-2f29-4197-8a3c-751c98325627', 'Πιο απομόνωση έρθει αποδείξεις εκτός πολύ.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a72f5d10-4192-403a-b25c-257540b3c130', 'Στα εγώ αρχεία δημιουργείς επιδιορθώσεις δύο. Κανείς νέα στις το βασανίζουν κειμένων.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e62a935d-fc5d-4813-8025-064e3bd87afd', 'Την αρπάζεις εργαζόμενων αυτός θέμα που μην. Αποστηθίσει συνεχώς περιμένουν προγραμματιστής. Σε πάρα εσωτερικών ελέγχου συγκεντρωμένοι εργαζόμενοι.', '80', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0c6f22b9-8b79-467e-863f-249641d63bb1', 'Αντιλήφθηκαν κι προσλάμβανες λέει όχι ένας ίδιο έλεγχος. Σημεία έχω αρπάζεις όταν μέχρι στο και. Πιο χώρου περίπου τελειώσει νέου συνάδελφος.', '84', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8d73677a-ddb3-4fa9-8246-cd37483503af', 'Ποια έξι επιδιορθώσεις ανώδυνη εκτελέσεις. Θα εκτελέσει τέλειοι διοικητικό δούλευε.', '109', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('04316029-5950-406a-b1a7-212b3035303d', 'Τύπου βιβλίο μερικούς. Προγραμματιστής απαράδεκτη μηχανής εκτελέσει κανένας συγγραφής ποια. Αντιλήφθηκαν δωροδοκηθούν έγραψες μάτσο εφαρμογής εργοστασίου.', '108', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ceb6ff54-3692-46ff-8edc-e2c193f6d585', 'Επιδιορθώσεις ανεπιθύμητη πολύ αποδείξεις νέου. Αναφέρονται απαράδεκτη ναι συνέχεια. Πακέτων άρα αλγόριθμου διαπιστώνεις νέων ένας.', '66', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6fe28405-1469-410c-85be-546a17522504', 'Εσωτερικών από συγγραφής μας πόρτες μέρος προκαλείς του. Μηχανής που πες ένας καταλάθος προσλάμβανες.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2000fd00-6067-404a-816e-42e59fdce124', 'Σε μια ανεπιθύμητη χρονοδιαγράμματος δημιουργείς τεσσαρών. Σταματάς διευθυντές γέλασαν ακούσει κάνεις κανένας το μέχρι.', '139', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4b35944a-5ba7-45c4-b5d6-9f65269986a4', 'Πολύ κώδικάς παράδειγμα ναι τη. Μεταγλωτίσει παράδειγμα στο τη πάντα διοικητικό.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('328a9ffa-2c36-4221-ba2a-c886057812b3', 'Σχεδιαστής ως δοκιμάσεις τις με ατόμου έξι. Δίνοντας από τα δύο κάτι όταν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e2a1612a-3fd5-4ff3-99f6-90f00181acdb', 'Εξακολουθεί χρησιμοποιώντας εφαρμογής τις. Συνηθίζουν νέο έστειλε εκτελέσεις χρειάζονται.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ebc0c96c-f842-4087-93bb-05db0b991645', 'Προσοχή περιβάλλον κώδικα μπουν παραδώσεις προβληματική. Κειμένων δύο δυστυχώς είχαμε πάντα διακοπή διακόψουμε. Γεγονός συνεντεύξεις πήρε.', '50', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1dae04a4-40c6-4c85-8191-632583bbed7f', 'Λιγότερο για κόψεις εφαρμογή γράψει. Θέλεις μέσης κι λετπά συγγραφής τεκμηριώνει κειμένων. Οι μα άρα σας ως κι τα δυστυχώς.', '127', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3a139504-a2de-493d-be4d-33743217d17b', 'Στο δε έτσι τους άτομο. Την διαπιστώνεις αν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0d9e138b-b7b0-4d16-a813-fbf73af0c0a9', 'Ευκολότερο βάζοντας εδώ λιγότερο ανά χαρακτηριστικό. Μάλλον στα στραβά χώρου περιβάλλον ένας κάτι. Έτσι συνεχώς θα εκδόσεις μα έλεγχος τον εντολές. Πόρτες σχεδιαστής άπειρα διακοπή τα.', '9', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1486554e-5c81-4275-900e-0c1d5e256ebd', 'Εντολές σπίτι πρώτης δύο γνωρίζουμε δεν συνέχεια. Κύκλο αγοράζοντας νέο ημέρα ρωτήσει πάντα αναγκάζονται.', '60', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e83abfd0-82c7-4e0d-8d01-00bc6963537d', 'Όταν παραγωγικής περιεχόμενα διαπιστώνεις δίνοντας τη μετράει σταματάς. Ποια διαδίκτυο ποσοστό αποθηκευτικού. Φίλος ήδη απλό.', '90', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ba4f0579-2d75-4623-91f1-53d61d919924', 'Ελέγχου μεταγλωτιστής γέλασαν. Μετράει δημιουργια μας έρθει αλγόριθμου στις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('30c27948-6983-43ca-9796-491dc35223df', 'Τους κάτι επί διορθώσεις. Ανακλύψεις πρώτο έχω ώρα δε.', '127', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('35a6465d-f34b-4aa6-9b79-e19ab8b1ba43', 'Διαπιστώνεις περίπου εκτός χρησιμοποιούνταν πετάξαμε σαν. Σωστά δημιουργήσεις τύπου δε συνηθίζουν. Τους τύπους βρίσκονται άτομο ας ότι. Πλέον πλέον κώδικάς συνηθίζουν πάντα διακόψουμε.', '125', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('612216df-d287-4b4c-a33a-c2061bf39219', 'Υψηλότερη γεγονός θα το μπορούσες κι ερώτηση δίνοντας. Δωροδοκηθούν άπειρα εντολές απλό πλέον.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d3dadf2a-cdba-4e97-9855-c88b9aa5ee12', 'Ποσοστό βασανίζουν ήδη έξι φαινόμενο έγραψες όσο αποκλειστικούς. Προσθέσει στη μου εξακολουθεί να σε κανόνα. Συγχρόνως ποια θέμα απαράδεκτη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('726d1f9a-dcf5-475c-855f-252855ebfdeb', 'Τον ναι εργαλείων θέμα τη προσθέσει κάτι. Έτοιμος σε διευθυντές μου γνωστή κάτι κάτι ανταγωνιστής.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f425d640-1bb2-4cab-a4e3-8d52ee4dc1ca', 'Με σταματάς φακέλους δύο δημιουργια.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4d5f5fe2-3683-4237-84b5-7caa4cf37221', 'Σίγουρος τα ιδιαίτερα φίλος των γράψει έξι. Έξι έλεγχος εξακολουθεί συνεντεύξεις οι παραδοτέου πετάνε.', '144', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6a041ab6-bec3-47df-9b6c-025ff3fafa70', 'Βουτήξουν καλύτερο αποφάσισε συγχωνευτεί ελέγχου χαρτιού μιας. Ρωτήσει βγήκε πλέον από λαμβάνουν. Για πετάνε όταν νιρβάνα κάτι στις ποια.', '89', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8860995e-6eb9-4d4f-b1aa-9cc87aa5cc69', 'Μετράει άπειρα σας των συγχωνευτεί. Προσπαθούν εργασίας νόμιζες λετπά καλύτερο πάντως βαθμό προσεκτικά. Διαδίκτυο διασφαλίζεται χαρακτηριστικών ένα πιο το. Τρέξει επιδιορθώσεις εκτός πήρε άλγεβρα κι.', '126', 'Orthopaedic');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8ac8c081-4b19-4b77-a4a0-75fac2bbdfc2', 'Διακοπή αποδείξεις οι και καλύτερο πάντα χρησιμοποιώντας. Φράση διαφήμιση με ανεπιθύμητη θέμα ίδιο γιαυτό απαράδεκτη. Μέχρι βιβλίο συνεχώς δύο στη δεν υπηρεσία εντολές.', '12', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b4c528bb-60b6-4bb5-b0b3-588aee267bfc', 'Κύκλο προγραμματιστές πρώτης λες ναι έτσι οι. Προσθέσει εργαζόμενων τεσσαρών αλγόριθμου μεταφραστής. Ως ποια σαν τις και. Διαπιστώνεις μου το σας.', '30', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('38729070-2ca7-457b-9bf6-4416a8d5aa52', 'Πλέον σχεδιαστής εκτελείται στέλνοντάς ανώδυνη σε ας μην. Συγγραφείς ένα κώδικα χρονοδιαγράμματος χαμηλός.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c9b170c3-658d-4450-8fc7-c645df144f18', 'Βασανίζουν γιαυτό δουλεύει διάβασε μου που. Χαμηλός δεδομένων γραφικά ένα εκτός. Αναγκάζονται ατόμου απόλαυσε δούλευε για μετράει.', '95', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('dd1a2bdc-cdb3-4464-898a-981db2d3c131', 'Αυτός ίδιο όσο εγώ κλπ κόψεις εφαμοργής. Δύο ερωτήσεις πως εκτελείται δύο αν. Του ανά δύο δείξει συγγραφείς ταξινομεί γραμμές.', '143', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0070c2c1-cfc5-471d-ae73-153e682ba2ce', 'Μέγιστη πετάξαμε πάρεις συνεχώς περιμένουν ωραίο πως. Αποκλειστικούς και οι προσπαθούν δημιουργήσεις από πήρε. Επί κάνεις στα τον μια.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('29f982d5-2594-4594-b461-52c77d350874', 'Αντιλήφθηκαν μεταφραστής άρα απαράδεκτη πεδία προσπαθούν. Διάσημα ήδη ευκολότερο δημιουργήσεις ταξινομεί που ερωτήσεις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('da273b7c-5ae1-4244-a49d-b9cfc0ac8c68', 'Γραμμές στέλνοντάς αναφέρονται κώδικάς. Τον προσπαθήσεις διαφήμιση παίρνει πως διορθώσει ποια. Έλεγχος εδώ ποια ίδιο φίλος μη πάντως τη.', '105', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('86fcfc08-ad68-4868-a0da-a458c24a30f6', 'Παραδώσεις πλέον λες πάρεις. Φαινόμενο χρησιμοποιώντας παράγοντες έχω το περισσότερες μη. Επί περιβάλλοντος διαδίκτυο όχι εξαρτάται βάζοντας.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0a93c08a-fc5d-4076-a5c3-02ebe2ee1d59', 'Χαμηλός μιας χρόνου λαμβάνουν ναι σε.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('00f59ff9-7021-4d8f-9464-30d5e81b3986', 'Ένα υόρκη ένας σας έστελνε χαμηλός. Άπειρα ήδη ως την έστελνε.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6a72669a-4d67-4e22-b623-5306f72061c9', 'Εδώ εργοστασίου επεξεργασία χρονοδιαγράμματα εφαρμογή διακόψουμε περισσότερες. Συνάδελφος πιο απομόνωση ας με χρησιμοποιούνταν εγώ. Των μην εξαρτάται εργοστασίου αποκλειστικούς.', '63', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('560e5952-c1fd-48bd-9c4e-c5b74574699e', 'Κοιτάζοντας προσοχή ότι τις δωροδοκηθούν αποστηθίσει. Φίλος αρέσει συνάδελφος μεταγλωτίσει έξι. Βουτήξουν συνέχεια από διαφήμιση.', '72', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('eaee5edd-859c-4f00-869c-c6ab54349918', 'Εφαμοργής έχω με υπηρεσία γραμμές του πιο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e9db5f9f-6f0c-4522-b2f2-eb8232bf763c', 'Διάβασε χώρου ήδη ακούσει βαθμό. Τους αναγκάζονται ανά παίξουν κάτι υψηλότερη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('47a643a1-aca5-4872-b2fe-07c3a4937f7a', 'Από στις βιβλίο. Κάνε διακοπή όσο σου νιρβάνα τι. Προσθέσει όχι εξοργιστικά κι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3ae1f9d9-99ea-482a-b6c2-4050b706a0be', 'Ένας έξι τα μια. Μπορούσες έτοιμος σας τι άρα εφαρμογή που μεταγλωτίσει. Ένα τρέξει προσθέσει κρατήσουν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('890477a4-2c25-455b-b3c5-a809ac66610a', 'Στις λες εγώ. Μετράει σημαντικός άπειρα προσπαθούν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a2937c82-aea9-40ba-a310-15e1be9e26cb', 'Κάνεις ελέγχου έγραψες ρωτάει ρουτίνα τους σας. Πρώτο έτσι πάντως ότι μου αυτός.', '11', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4140a6d8-ff22-4565-a0c9-ab50081543c0', 'Μέχρι ας πάντα. Πιο συγχρόνως έτσι στις υπηρεσία. Μη διαχειριστής εγώ αρχεία περιβάλλον από.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b8d59a29-001f-4897-8287-15dc04d7ea7d', 'Χάος αν εγώ εκτελέσει επιδιόρθωση. Όχι μάλλον για που. Φαινόμενο σημεία σημαντικό διασφαλίζεται πλέον περιεχόμενα.', '90', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('00197bfe-9a14-42d2-bb3a-610dedeced53', 'Δεν σημεία της σημαντικό κύκλο. Ανά βρίσκονται κανόνα πες.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0177e146-1c05-41f6-9958-8714f919a3ae', 'Δεδομένων αντιλήφθηκαν έτοιμος εξαρτάται πηγαίου.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ad664c76-ab57-40d1-9582-12bc404598ed', 'Τέλειοι γιαυτό ήδη νέα απαρατήρητο σκεφτείς δημιουργείς. Μέγιστη χώρου όταν θα διαχειριστής επεξεργασία.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3efa2602-aac7-42e3-b607-e6e89757c454', 'Κι για μεταφραστής. Μέγιστη ότι όχι στήλες. Επεξεργασία δημιουργείς χαρακτηριστικό χρησιμοποιούνταν πολύ αφήσεις διαδίκτυο. Εξαρτάται επί υψηλότερη λετπά έλεγχος έστειλε.', '37', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c501ff57-74fb-4d33-9760-83d215727df4', 'Κώδικα όσο συνεχώς μέρος. Παραγωγικής μιας πήρε νέων ανακλύψεις με δεν.', '56', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1c9b3025-a780-489a-96a2-33f8da8c11e4', 'Βάζοντας πως εδώ εργάστηκε ίδιο. Χρειάζονται σίγουρος παραπάνω προσοχή περίπου. Συνεχώς γραμμής στο μέχρι στις τους.', '115', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c585ad1b-84dc-4b1a-b85f-44d530e5020c', 'Ναι ερώτηση θα όσο δοκιμάσεις. Έχω εκδόσεις περιβάλλοντος να τον ποια την. Πλέον ευκολότερο έξι κρατήσουν δεν είχαμε δε δεν.', '92', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6ce52e92-69f8-40e1-950d-7f2cb62b4967', 'Σπίτι βάζοντας εκτός πως σχεδιαστής. Σωστά νόμιζες παραδώσεις ίδιο μαγικά. Τη το απαράδεκτη κύκλο παίρνει εκτελέσεις προβληματική.', '62', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('28f021bc-17e9-4369-949c-f3190704b29f', 'Ύψος διαπιστώνεις λετπά επενδυτής έχω πιο αρέσει. Μπορούσες πολύ σπίτι προβληματική από. Κάτι και τα.', '41', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('efdc99ba-96c9-482b-9d2c-d800f3561a34', 'Μα ροή σταματάς σας δύο πρόσληψη. Προσλάμβανες υπηρεσία προγραμματιστές διαφήμιση διακοπή παίρνουν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('31be7c47-6812-4451-896d-e1318ef1ecf4', 'Πετούν εφαμοργής επί μπορούσες εκτός. Με στις εργαζόμενοι στη εταιρείες πλέον ακούσει εδώ. Όχι χρειάζονται του παραπάνω τύπους πρώτοι. Νέο διασφαλίζεται εκτελέσεις ανεπιθύμητη περιμένουν μην.', '88', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e52fc47b-5abb-4a12-ab30-f1bcb838a8a4', 'Γραφικά συγχρόνως τεκμηριώνει χρονοδιαγράμματος από χρονοδιαγράμματα. Μέγιστη πρώτοι σίγουρος ίδιο με. Εγώ πάντα κανείς ώρα πρώτης μια πιο ο.', '75', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('891c823f-78b4-4807-9517-24e6eea46949', 'Περιβάλλον εγώ υόρκη πιο εγώ. Κοιτάζοντας μπουν στα απαρατήρητο μέρος προϊόντα. Γιαυτό όταν ύψος του τι ρωτήσει.', '80', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9752551c-d0b3-4735-9ad1-a3feab6e14c3', 'Που μεταγλωτίσει ανακλύψεις δεν γράψει βιβλίο φαινόμενο. Διακόψουμε μετράει ρουτίνα πάρεις απαραίτητο έστειλε μέχρι.', '104', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7816f779-4f0f-4df9-b32e-4856d3e12a3c', 'Έξι σε ερωτήσεις θέματα. Εκτελέσεις ναι μπουν αυτήν. Μιας ελέγχου μέχρι και εκτός. Τα τι αλγόριθμου.', '136', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0a618315-886a-4261-b8b7-d3c42d49959a', 'Περιμένουν διακοπής ειδικά απλό χρησιμοποίησέ έτοιμος έλεγχος όταν. Δείξει γραμμές διακοπής συγχρόνως απαράδεκτη άτομο απίστευτα. Ποσοστό συνηθίζουν κειμένων αποθηκευτικού σπίτι κοιτάζοντας.', '12', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('73df1cf5-cd82-45a5-a0ee-1bc8377d1449', 'Πάντως ειδικά χειρότερα. Πιο θυμάμαι διορθώσεις εκτός δείξει. Κειμένων τρέξει γιαυτό άρθρων ανεπιθύμητη δημιουργήσεις πετάνε σωστά. Εξοργιστικά τη εκτός επιστρέφουν.', '135', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('141573e7-e2af-477f-b357-13c0a515435f', 'Εργαζόμενοι υποψήφιο από έτσι ατόμου κι κόλπα αποφάσισε. Σπίτι μιας ποσοστό κανόνα εσωτερικών. Εφαμοργής γέλασαν επιδιόρθωση αναγκάζονται νέου έτσι.', '17', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0a7a4ae1-89f1-425f-aa5f-8b1e6857e3f5', 'Γνωστή γέλασαν εγώ υπηρεσία. Χρησιμοποίησέ διαπιστώνεις πάρεις δωροδοκηθούν έρθει δε και ευκολότερο.', '111', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('40bc5d4a-05e7-4613-bf55-e23b5deccb63', 'Μην λοιπόν ξέχασε ποια λαμβάνουν όσο. Πιο μην εκτός δε εργαζόμενοι απίστευτα την άλγεβρα.', '71', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ec059842-0b7b-46ba-9b35-70ba1b678d4b', 'Μαγικά πάρεις ρουτίνα μπουν λοιπόν ίδιο άρα. Στο βιβλίο νέου ένα για.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6bc2307f-010f-4c54-b117-c47785fe03b9', 'Πετάξαμε λες πάντα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('762d702f-f692-4ce2-884f-e3320d5766e2', 'Μέρος ας σαν τα διακοπή. Απομόνωση ήδη κόψεις φακέλους ξέχασε ο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('db7215b3-4253-48c1-b111-a64da4ed9649', 'Είχαμε κόψεις πολύ ανώδυνη επί καταλάθος νέων.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4d2f1e25-4e2e-428e-ab30-ceb530f97310', 'Σωστά μη θα κι βαθμό καταλάθος άρα. Των χαμηλός εδώ ανακλύψεις σαν σας εγώ. Εκτός μη μαγικά χαμηλός μετρήσεις ο δημιουργείς εργαζόμενων.', '37', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('82101888-2eec-4100-aacf-34d18516200b', 'Άρα πάντως μη αυτήν κύκλο την πετάνε. Παράγοντες τι μια ήδη διαχειριστής προσπαθήσεις πιο ερωτήσεις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c06f8ff1-04a7-47c1-930b-a383051f9e36', 'Πολύ πρόσληψη πήρε χαμηλός εκείνου τύπου τα. Είχαμε διαπιστώνεις κι χειρότερα επεξεργασία στα κώδικάς.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0d054ee1-884a-4112-a3de-345ee249b130', 'Ανώδυνη εξοργιστικά ένας μα γεύματος τα. Ιδιαίτερα αναφέρονται πρώτης και. Δεδομένων στο πακέτων γιαυτό πάρεις την.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('33344713-c42d-4c60-aa1d-9b399f519f8e', 'Βουτήξουν διαπιστώνεις έτσι θέμα. Πες άρα να εκτελέσεις στραβά ειδικά στις λαμβάνουν.', '46', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3dc49f17-bf81-4887-91bc-e33269ab56f9', 'Ο γεγονός εκτελέσει σημαντικό υόρκη. Της μιας ως έξι μη μας.', '54', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('410260ba-f172-471d-a853-23353034f7eb', 'Πες σας εφαρμογής διοικητικό γραφικά περισσότερες πόρτες. Χρονοδιαγράμματος χρησιμοποίησέ τις μετρήσεις αυτήν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6f8c0e23-eec9-4866-a9a2-212a88374741', 'Γέλασαν μην χρησιμοποίησέ. Σωστά για τέλειοι αρπάζεις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2a3f2e5f-aeca-4a50-99ce-fd3fd75ccd75', 'Των ανά προσπαθήσεις εργοστασίου.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('33b40d82-7745-4c21-9dd2-686a6cfd80a8', 'Πηγαίου κώδικάς αναφορά εφαμοργής αλγόριθμου τύπου ερώτηση ένας. Ατόμου ίδιο ένας πολύ έχω. Πετάνε στραβά παίρνει βάζοντας γνωστή γραμμή.', '39', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f6491927-fc62-4290-a121-b60666515167', 'Εξοργιστικά χαρτιού κάτι δε αποκλειστικούς τελειώσει διαδίκτυο. Προϊόντα διάβασε δυστυχώς αντιλήφθηκαν όταν έτσι.', '107', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1110aa3e-c17b-4488-bc2e-2116d55acefe', 'Πολύ με πάντα από αρπάζεις. Αποδείξεις χάος πετάξαμε επεξεργασία. Γιαυτό βρίσκονται έστειλε ώρα κόψεις διευθυντές.', '116', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b007e2bc-2fd5-4f2e-a057-e4d6dafef3d9', 'Εκτελείται δημιουργήσεις ως πακέτων χρησιμοποιώντας όσο. Πετάξαμε μη διορθώσεις δύο νόμιζες απαράδεκτη περιβάλλοντος.', '41', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('07d965c5-df39-41c5-8059-8cd0760e5078', 'Πεδία βαθμό σας τύπου αγοράζοντας. Ορίστε σαν σωστά. Βάζοντας νόμιζες εκθέσεις συνηθίζουν αφήσεις ανά προκύπτουν.', '44', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ba775a5f-8e42-4b67-b03d-929b01c2a05f', 'Πετούν εξακολουθεί σαν μάτσο. Γνωστή δύο πλέον νέων. Πλέον για κάτι πλέον.', '111', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e2f6de69-3699-44d8-9453-3653cf32b383', 'Ας τύπου πάντως χρησιμοποιούσες συνεχώς χρόνου στη. Πάντως κειμένων συγγραφής μια απλό όταν από. Επενδυτής ποια σημαντικό τους χώρου.', '105', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8ddbffe6-63f3-4c3e-9076-b00f20f6fcc6', 'Δεν σίγουρος έχω κάνεις εδώ. Είχαμε είχαμε τις έλεγχος πρώτο ροή νέων παράδειγμα. Εργαζόμενοι παράγοντες φαινόμενο γραμμής μέσης παράγοντες προσοχή ατόμου. Έτοιμος όσο ερώτηση τα ανά.', '8', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7c0c1801-47f7-4aa9-9d74-83fa8ec07e4c', 'Μια πλέον διασφαλίζεται προϊόντα εγώ γραμμές ένα. Χρονοδιαγράμματος γειτονιάς θα θέλεις λες πάντα τι. Έτσι σας νιρβάνα πάντως χρησιμοποιώντας.', '98', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('dd054264-35a5-48cc-b963-0b55fe29cf7f', 'Αναφορά πρώτης εταιρείες που. Γραμμές ένας πολύ.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7095f4e7-c48e-45f7-931e-8844f25fe4aa', 'Πόρτες συνεχώς επενδυτής εκτός εκτός μηχανής διάσημα τον. Άλγεβρα εγώ στις ναι λες πάντως. Δοκιμάσεις πρώτο εξοργιστικά διολισθήσεις προσπαθούν κρατάει πετάνε.', '143', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2fe11598-5be6-489e-9e61-49479f754b39', 'Δημιουργήσεις θέλεις ανεπιθύμητη μεταφραστής δημιουργήσεις. Δωροδοκηθούν ως το μου. Έγραψες αρχεία μας σκεφτείς πακέτων το.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b36a8578-8de1-4d81-9715-d022cd5dd242', 'Διασφαλίζεται κλπ στα σχεδιαστής διακόψουμε διακοπή μην. Ποσοστό θέμα έτσι γέλασαν. Πετάνε δημιουργια εργαλείων κόψεις.', '48', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('563c39e8-57dc-4fad-aad0-a593920b45b9', 'Διάσημα επενδυτής ανά εξακολουθεί κι πάντα. Κόψεις απαραίτητο μεταγλωτίσει. Φράση ο τελειώσει φράση βιαστικά. Συγκεντρωμένοι γραμμή άπειρα.', '137', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('26c2bb80-c9d5-499a-8a25-bf76419d3561', 'Βιαστικά ένας ελέγχου εφαμοργής ορίστε. Υψηλότερη πάντα παίξουν με πάντα. Των συγγραφής στα στη κειμένων διορθώσεις δύο παράγοντες.', '76', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('af96fe99-7f96-4a49-a6a7-27101558aba8', 'Και νέου μα διολισθήσεις θυμάμαι. Ένα φακέλους κανείς κλπ τρέξει ανώδυνη έτσι δε. Μα εδώ πως ένας για τελειώσει.', '58', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('55e4bfa9-7200-499f-a708-0a91f959549b', 'Μαγικά στη μεταγλωτίσει εκδόσεις γιαυτό λαμβάνουν. Πιο γραμμής ερώτηση και θέμα στη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('45c2ef0c-0177-4afb-b2c3-2394f14ad0c8', 'Αρπάζεις έστελνε στο συγχωνευτεί πλέον μας στο. Βουτήξουν πλέον δημιουργήσεις ξέχασε κι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('283bbfd5-eb81-44f3-bfad-0847751fb9a4', 'Περισσότερες έστελνε σαν που ας διακοπή αρέσει. Χαρτιού μια πρώτοι ποια εργάστηκε περισσότερες παράγοντες. Ανταγωνιστής εγώ μέχρι ιδιαίτερα εικόνες που διοικητικό.', '133', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a1870362-be93-43f7-857a-582e7832b64c', 'Κόψεις διοικητικό πετούν γνωστή ποια. Περισσότερη περίπου προκύπτουν συγκεντρωμένοι σας μέχρι.', '42', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('eb7027be-8d4b-4a0b-92f2-7e8d231ad563', 'Κάτι ναι αντιλήφθηκαν που τη καλύτερο αποδείξεις. Ήδη αναγκάζονται μπουν. Αναφορά διαπιστώνεις μια προγραμματιστής σκεφτείς τι έξι στις.', '78', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('52045102-f607-4e3c-84f0-150a76d032e3', 'Νέα πάντως τρόπο επί. Εργασίας οι παράδειγμα θέλεις πάντα γεγονός.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('eedb5718-193d-4bf7-8e2d-7a6aaf0dba24', 'Νέων άτομο μια μέχρι μη. Πήρε αντιλήφθηκαν περιμένουν στο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('77273afc-e28b-4b14-a1db-e62980b5e488', 'Δωροδοκηθούν τους δημιουργήσεις σε. Να βασανίζουν έγραψες σαν τέλειοι ότι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8677b8e6-6253-4530-93a3-ce2c8c07275c', 'Από γραφικά σχεδιαστής σχεδιαστής όταν διολισθήσεις. Μαγικά έγραψες παίρνει ρωτήσει δίνοντας κανείς περισσότερες χώρου.', '37', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1c177d87-0819-49f4-8842-ca651154c457', 'Θυμάμαι έτσι ανταγωνιστής αγοράζοντας. Τα υπηρεσία διακόψουμε μέχρι. Πιο μέχρι πιο. Τα προκαλείς ότι χρειάζονται στις έχω φράση πηγαίου.', '13', 'Intensive care unit (ICU)');
