INSERT INTO media (media_id, path, description) VALUES ('1', '/media/images/image_eveniet.jpg', 'Αυτός κι πρώτοι φίλος εκτελέσεις επιστρέφουν πως. Τις ξέχασε ίδιο.
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('1', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('2', '/media/images/image_quia.jpg', 'Συνέχεια στα παίξουν. Πάντα γνωρίζουμε περισσότερη διάβασε τοπικές μέχρι γέλασαν γραφικά.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('2', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('3', '/media/images/image_earum.png', 'Λετπά παραγωγικής δυστυχώς ας.
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('3', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('4', '/media/images/image_eveniet.jpg', 'Πάντα με δεν μέγιστη.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('4', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('5', '/media/images/image_soluta.jpeg', 'Κρατάει λοιπόν άρα προσεκτικά εταιρείες βουτήξουν δημιουργήσεις. Αρέσει τελειώσει ανεπιθύμητη νόμιζες μάθε παράγοντες.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('5', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('6', '/media/images/image_dolore.jpeg', 'Κι κάνεις ροή ανακλύψεις. Μια για πως επί. Δημιουργείς ήδη ημέρα πλέον. Διορθώσεις μιας λαμβάνουν μια.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('6', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('7', '/media/images/image_totam.jpg', 'Έχω ζητήσεις λες καταλάθος και γέλασαν πάρεις. Κοιτάζοντας παραγωγικής τους περιβάλλον ρωτήσει όταν. Σημαντικό πλέον μπορούσες χρειάζονται μετρήσεις του.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('7', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('8', '/media/images/image_voluptas.jpg', 'Υπηρεσία αυτός περισσότερη βασανίζουν διάσημα έξι διάσημα. Όταν αναγκάζονται χώρου δυστυχώς της.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('8', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('9', '/media/images/image_error.jpg', 'Επί επιστρέφουν οι τις. Ο στα περιμένουν κανείς καταλάθος ύψος.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('9', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('10', '/media/images/image_adipisci.jpg', 'Λετπά στέλνοντάς αφήσεις ένας την χρησιμοποιούνταν κάνεις ότι. Λέει προσεκτικά δεν σκεφτείς μας. Νέων ώρα ότι βγήκε πάντως αντιλήφθηκαν.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('10', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('11', '/media/images/image_eaque.jpeg', 'Ας επεξεργασία απαράδεκτη λες δυστυχώς. Μεταφραστής ωραίο εκτός κοιτάζοντας μιας.
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('11', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('12', '/media/images/image_optio.jpg', 'Σου ημέρα του ανά πήρε μηχανής στις διαφήμιση. Γεύματος σωστά δυστυχής προκύπτουν.
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('12', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('13', '/media/images/image_voluptate.jpeg', 'Μετράει κάτι ήδη χαρτιού τα ίδιο. Στη δίνοντας κρατάει. Διαχειριστής έχω λοιπόν και έστελνε σημεία. Ειδικά οι άρα.
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('13', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('14', '/media/images/image_laborum.png', 'Εγώ εφαρμογή αν μην συγχωνευτεί στο. Συνεχώς κύκλο πηγαίου απομόνωση.
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('14', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('15', '/media/images/image_facilis.png', 'Τον διορθώσει έτοιμος αποδείξεις παίρνει πάρα. Πολύ παραδώσεις προσπαθήσεις σωστά δωροδοκηθούν κάνε αθόρυβες ημέρα. Γραμμή της πες πήρε.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('15', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('16', '/media/images/image_incidunt.png', 'Κι μέχρι τοπικές μέρος. Πιο και κι μπουν ανά.
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('16', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('17', '/media/images/image_cum.png', 'Πες νιρβάνα ο στο. Πήρε προκύπτουν σταματάς δύο χρησιμοποίησέ γράψει μέσης.
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('17', 'doctor_id');
