INSERT INTO media (media_id, path, description) VALUES ('646', '/media/images/image_nam.jpg', 'Μετράει μιας πρώτης ναι μιας άτομο. Ποια εδώ σε το σταματάς διοικητικό.
INSERT INTO room_media (media_id, room_id) VALUES ('646', 'room_id');
INSERT INTO media (media_id, path, description) VALUES ('647', '/media/images/image_eaque.jpeg', 'Στέλνοντάς εκθέσεις στο ας διευθυντές χαρακτηριστικών. Δωροδοκηθούν πλέον αν εικόνες. Βγήκε πάντως αλγόριθμου αποκλειστικούς τον δημιουργια στραβά.
