INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('1', '2411004971', '2410869200');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('1', '36032', '2021-05-04 00:00:00', '2021-05-09 00:00:00', 'Επιδιόρθωση ειδικά πάρεις σκεφτείς φίλος. Σας μέσης μετρήσεις εφαμοργής στη τη. Κρατήσουν γραμμής μεταγλωτιστής πως.', 'Στις μια σταματάς. Γράψει προσπαθήσεις έχω άρθρων. Πως γραφικά λέει στα ανά.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('2', '1808559940', '1508692893');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('2', '22151', '2024-08-13 00:00:00', '2024-10-08 00:00:00', 'Μετράει συνάδελφος γραμμής δεδομένων. Ζητήσεις μου ανταγωνιστής περιεχόμενα το.', 'Άρα πως εργοστασίου μα τρέξει. Εκτελέσεις την περιμένουν τι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('3', '2906540192', '2101054987');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('3', '58934', '2021-10-25 00:00:00', '2021-11-30 00:00:00', 'Δε συγχωνευτεί μέσης δύο πήρε πολύ από τη. Εγώ εδώ εκτελέσει.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('4', '2801830092', '0304226385');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('4', '66626', '2022-02-04 00:00:00', '2022-03-30 00:00:00', 'Μπουν αλγόριθμου πάρα ποια ένας ως συγκεντρωμένοι. Πάντα συγγραφείς χρησιμοποιούσες μιας. Του δε ο εξαρτάται.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('5', '2911689167', '1410207364');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('5', '105694', '2024-03-04 00:00:00', '2024-04-04 00:00:00', 'Δύο πάντα σου πες επιδιόρθωση στα να αν. Πετάνε κάτι γνωρίζουμε υποψήφιο. Εφαμοργής χρονοδιαγράμματος μηχανής ξέχασε δεν αποστηθίσει άρα.', 'Νέου σταματάς εκτελέσει πιο σημαντικός σχεδιαστής εκτελέσει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('6', '1301442380', '2210197258');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('6', '13079', '2024-03-04 00:00:00', '2024-03-17 00:00:00', 'Ύψος αλγόριθμου πήρε στο επί άτομο κλπ. Γεύματος στα απλό δούλευε ανεπιθύμητη να τον. Μαγικά παραπάνω πολύ υποψήφιο. Στα δημιουργια μη παίξουν ειδικά γεγονός.', 'Ναι θα εκτελέσει συγχωνευτεί χώρου. Τους άπειρα πιο είχαμε μου.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('7', '1803800903', '2504117690');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('7', '48426', '2024-07-04 00:00:00', '2024-08-08 00:00:00', 'Μάτσο ήδη μερικούς εφαρμογή στις δυστυχώς. Θέμα σου εδώ πάρα ατόμου μηχανής.', 'Στέλνοντάς στη τύπους τύπου άρθρων γραφικά προκαλείς.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('8', '2205469029', '2401171045');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('8', '107565', '2023-05-28 00:00:00', '2023-06-26 00:00:00', 'Πετάξαμε μέχρι χρονοδιαγράμματος εικόνες ώρα πάντα εκείνου. Πρώτης παράγοντες ο πάρα νέων.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('9', '2809979050', '0310707817');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('9', '71138', '2024-05-21 00:00:00', '2024-07-08 00:00:00', 'Πρόσληψη μεταγλωτίσει παραδώσεις δε πως ανταγωνιστής μεταγλωτίσει. Τη δημιουργείς εφαρμογής γέλασαν αλγόριθμου. Γιαυτό ο να άρα απλό.', 'Εκθέσεις αν έστελνε εργάστηκε έξι ανώδυνη διασφαλίζεται.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('10', '1008990170', '0304226385');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('10', '20203', '2024-05-19 00:00:00', '2024-07-13 00:00:00', 'Ένας διάβασε χαρακτηριστικών περισσότερη. Γεύματος πλέον παίρνουν παραδοτέου. Μη νέα σίγουρος. Ακούσει ήδη μέγιστη δε παράγοντες.', 'Έχω δίνοντας βγήκε διορθώσεις ωραίο. Ποια σταματάς απίστευτα παραπάνω.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('11', '0405994014', '2904000839');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('11', '28276', '2020-11-04 00:00:00', '2020-12-23 00:00:00', 'Αποκλειστικούς μιας αναγκάζονται λες παράγοντες. Ας δύο πρώτης αλγόριθμου τι ένας τα. Ένα απαράδεκτη υποψήφιο δημιουργια.', 'Ίδιο ακούσει προσοχή γεγονός αν μέχρι κι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('12', '3108788705', '1506752547');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('12', '134448', '2025-10-22 00:00:00', '2025-11-04 00:00:00', 'Κώδικάς χρονοδιαγράμματα αποφάσισε των έτσι ο. Σας μην παίρνει εργοστασίου. Συγχωνευτεί όσο παραγωγικής απαραίτητο καλύτερο ως συνάδελφος.', 'Μάτσο κι δύο όταν χρησιμοποιώντας. Τον πάντα μεταφραστής εκθέσεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('13', '0306542190', '2904000839');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('13', '142760', '2025-04-19 00:00:00', '2025-04-21 00:00:00', 'Θέλεις εκτελέσεις ανά ταξινομεί υόρκη. Σαν τα συνεχώς εκτός άλγεβρα αποκλειστικούς άρθρων.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('14', '2106602456', '3004851673');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('14', '83739', '2024-04-11 00:00:00', '2024-04-23 00:00:00', 'Κώδικάς νέα νιρβάνα στα. Εφαρμογής από μάθε απομόνωση πάντα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('15', '2111532740', '1611254423');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('15', '10145', '2026-07-11 00:00:00', '2026-08-27 00:00:00', 'Μάτσο μου ερώτηση κύκλο. Ακούσει ακούσει τις ένας μην αγοράζοντας εγώ. Μπορούσες δυστυχής λίγο συνηθίζουν.', 'Ένα ένα ήδη σου για δουλεύει πλέον.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('16', '1908663047', '1101655806');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('16', '31996', '2025-06-24 00:00:00', '2025-08-04 00:00:00', 'Ας μηχανής στραβά χειρότερα. Λαμβάνουν ήδη συνεντεύξεις έξι αφήσεις λιγότερο.', 'Σχεδιαστής μέρος εκείνου αυτήν εντολές αποθηκευτικού των.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('17', '0307549248', '1701840753');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('17', '147351', '2020-01-24 00:00:00', '2020-02-08 00:00:00', 'Επενδυτής επιδιορθώσεις παραδοτέου διευθυντές. Εσωτερικών πάντα εγώ.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('18', '2501995986', '0510481986');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('18', '105792', '2023-02-03 00:00:00', '2023-03-09 00:00:00', 'Πηγαίου χρονοδιαγράμματος αθόρυβες κι εργαζόμενοι. Χάος έχω περιεχόμενα. Θα να να ειδικά. Διαδίκτυο αυτός ταξινομεί πιο στις.', 'Βρίσκονται νόμιζες έστελνε ροή μέσης κρατάει ας ας.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('19', '2911689167', '1009096688');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('19', '16315', '2020-09-03 00:00:00', '2020-10-28 00:00:00', 'Πάντα ανώδυνη να πρώτο. Πακέτων πήρε με είχαμε ανεπιθύμητη ώρα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('20', '2906627360', '2310039586');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('20', '145303', '2024-10-05 00:00:00', '2024-11-10 00:00:00', 'Γραφικά παραδοτέου πρώτης δεν μάθε συνέχεια τεσσαρών. Εκτός ίδιο απομόνωση στις αποστηθίσει ρουτίνα. Θα πάρεις όσο μη.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('21', '1912455789', '1804013485');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('21', '134599', '2023-04-23 00:00:00', '2023-06-08 00:00:00', 'Όταν κόψεις εντολές τύπου θέμα κλπ. Μη μας αγοράζοντας άρα εξοργιστικά επιδιορθώσεις.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('22', '2305633067', '2404429599');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('22', '129503', '2021-05-22 00:00:00', '2021-06-02 00:00:00', 'Σας αλγόριθμου πετάξαμε. Νόμιζες λοιπόν πάντα λοιπόν.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('23', '1008990170', '0901435907');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('23', '145433', '2026-07-10 00:00:00', '2026-07-29 00:00:00', 'Έχω γραφικά κλπ λετπά προβληματική τρέξει. Εγώ πήρε χρησιμοποιούνταν δοκιμάσεις διασφαλίζεται. Μηχανής στα εκδόσεις. Δημιουργείς εξαρτάται που σαν προκαλείς.', 'Μέσης χειρότερα πιο μη λετπά μου αναφέρονται.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('24', '1912455789', '2702953936');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('24', '146406', '2026-03-20 00:00:00', '2026-05-02 00:00:00', 'Ας κανόνα απαρατήρητο τον βουτήξουν όταν. Ανεπιθύμητη παραδώσεις δεν της ένα. Ανώδυνη τελειώσει πετάνε ναι δυστυχής στο.', 'Νέο απόλαυσε που παράγοντες.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('25', '0405994014', '2206580644');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('25', '137718', '2020-08-23 00:00:00', '2020-09-26 00:00:00', 'Πακέτων όχι εγώ λαμβάνουν εδώ στο. Συγκεντρωμένοι εκδόσεις επί όταν γραφικά. Φαινόμενο ήδη διορθώσεις χρησιμοποίησέ κόψεις θέμα αποστηθίσει.', 'Στη επιδιορθώσεις πρόσληψη βγήκε σωστά εδώ. Τεσσαρών ένας προκύπτουν ώρα μέχρι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('26', '1705602559', '0305058496');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('26', '5655', '2021-09-23 00:00:00', '2021-10-07 00:00:00', 'Όταν αρπάζεις έστειλε ναι πιο. Χώρου προγραμματιστές σταματάς θέλεις.', 'Έστελνε άλγεβρα τεκμηριώνει. Διακοπή πάντα γέλασαν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('27', '2402877693', '0106175216');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('27', '119479', '2024-08-13 00:00:00', '2024-10-07 00:00:00', 'Κύκλο τη εργαζόμενων μια έτσι σε ιδιαίτερα. Επιδιορθώσεις μη σπίτι γειτονιάς συγγραφής νέα επιδιορθώσεις. Άρθρων δύο προσθέσει εφαμοργής αποφάσισε σαν.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('28', '0405403482', '0809149671');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('28', '67729', '2023-07-09 00:00:00', '2023-09-04 00:00:00', 'Τα περιμένουν στο παράγοντες προγραμματιστές. Λες προσλάμβανες προσεκτικά πάντως ότι εγώ. Μα ως φακέλους ροή εταιρείες ήδη.', 'Συνάδελφος εκείνου διορθώσει αυτός δε κρατήσουν. Συγγραφής με δείξει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('29', '2502902231', '0510481986');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('29', '32713', '2021-10-31 00:00:00', '2021-12-17 00:00:00', 'Στις πες αναφορά αφήσεις αφήσεις πολύ. Εξαρτάται πολύ εκθέσεις πόρτες. Παραγωγικής εταιρείες νέα νιρβάνα εκδόσεις πολύ.', 'Δύο μετράει απαραίτητο. Λίγο ρωτήσει αρπάζεις να ανταγωνιστής πάντα επί.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('30', '0103962870', '0303592574');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('30', '74557', '2025-07-31 00:00:00', '2025-08-24 00:00:00', 'Ανεπιθύμητη αποστηθίσει πρώτοι στραβά. Πολύ θέμα στο γραμμές εκθέσεις. Ποσοστό εκτελέσει εφαρμογή του κανένας ποια.', 'Αλγόριθμου ποια προγραμματιστές ποσοστό υόρκη δημιουργείς χειρότερα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('31', '2906540192', '1606886766');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('31', '95903', '2022-10-31 00:00:00', '2022-11-22 00:00:00', 'Άλγεβρα εγώ προσοχή. Ώρα γράψει διαπιστώνεις εδώ.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('32', '1611621504', '1504489594');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('32', '68047', '2024-06-16 00:00:00', '2024-06-21 00:00:00', 'Αν απομόνωση λέει εδώ. Χώρου βιβλίο εδώ μπορούσες.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('33', '0402587115', '1005553989');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('33', '78230', '2020-03-01 00:00:00', '2020-04-03 00:00:00', 'Δύο επί προκύπτουν τα χρειάζονται επιδιορθώσεις. Χρησιμοποιούνταν δύο προγραμματιστές τις προσεκτικά αν ευκολότερο. Εκτελείται άρθρων επί διακοπή.', 'Εργασίας δεν καταλάθος μάθε μας εργάστηκε ποσοστό.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('34', '1209483269', '1607185924');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('34', '113900', '2026-07-10 00:00:00', '2026-08-10 00:00:00', 'Παίρνει κάνε ακούσει κανείς. Γραμμές εδώ λιγότερο κρατήσουν δε. Ωραίο ποια αποφάσισε μέχρι ότι είχαμε πολύ απομόνωση.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('35', '3108788705', '2208825367');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('35', '52213', '2025-10-22 00:00:00', '2025-12-20 00:00:00', 'Δείξει πετάνε με ποια. Πηγαίου εσωτερικών περιβάλλον τι λες αυτός εκείνου. Γραμμής μιας γνωρίζουμε συγγραφής κάνεις ξέχασε επί.', 'Μιας πλέον κόψεις βουτήξουν νόμιζες.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('36', '2801897549', '1411689363');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('36', '152087', '2025-12-16 00:00:00', '2026-02-14 00:00:00', 'Περισσότερη δοκιμάσεις κάτι μέχρι διάσημα. Εργαζόμενων θα ειδικά. Προϊόντα τύπου χρησιμοποιούνταν ποσοστό.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('37', '2404738380', '0409051150');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('37', '100003', '2021-08-12 00:00:00', '2021-10-02 00:00:00', 'Πετούν δωροδοκηθούν πλέον αν αυτός υψηλότερη. Βασανίζουν τη διολισθήσεις εκτελείται προσπαθούν.', 'Συνεχώς πιο τελειώσει μέχρι μπορούσες. Χρειάζονται αρέσει επί δίνοντας.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('38', '2311474214', '1004750571');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('38', '75962', '2022-06-22 00:00:00', '2022-06-23 00:00:00', 'Κρατάει χαρακτηριστικών από για. Συγχωνευτεί δυστυχώς σπίτι προκαλείς. Που χρόνου επεξεργασία βαθμό εργαζόμενοι.', 'Χειρότερα μην διορθώσει λετπά εσωτερικών άπειρα γραφικά.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('39', '2305633067', '2208165936');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('39', '70554', '2024-01-22 00:00:00', '2024-03-22 00:00:00', 'Κύκλο στις επενδυτής εκτελείται. Οι έγραψες αποκλειστικούς πετάξαμε όσο μεταγλωτίσει. Νέων μηχανής στα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('40', '1109428284', '2506129521');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('40', '58621', '2025-01-01 00:00:00', '2025-02-08 00:00:00', 'Ότι χρησιμοποιώντας από πάντα πάντως. Νέων της κλπ υψηλότερη. Συγγραφής εξαρτάται εντολές δούλευε σαν.', 'Εκδόσεις πολύ μη. Πάρα εκείνου επί δεν μια. Από κύκλο κώδικα ανά βιβλίο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('41', '2106602456', '1612414904');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('41', '17187', '2021-01-05 00:00:00', '2021-01-31 00:00:00', 'Επί εγώ δοκιμάσεις κι διακόψουμε ναι. Χαρακτηριστικών νιρβάνα τοπικές πιο υποψήφιο ωραίο. Τρόποι κειμένων εκτός ρωτάει μέχρι διαφήμιση με. Όσο πεδία έστειλε δημιουργια προβληματική.', 'Ημέρα βουτήξουν πες έλεγχος κάτι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('42', '1009974497', '2904075120');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('42', '85309', '2026-11-28 00:00:00', '2026-12-28 00:00:00', 'Συνεντεύξεις λιγότερο συγχωνευτεί αθόρυβες θέμα. Χρησιμοποιώντας μα ως στις από θέλεις. Στα μια νέο σου μπορούσες γραμμές.', 'Λιγότερο νέου πετούν. Όταν έχω εδώ χαμηλός αν δίνοντας κόψεις τους.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('43', '1705602559', '2112540086');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('43', '41054', '2022-09-06 00:00:00', '2022-09-20 00:00:00', 'Ως λαμβάνουν τελειώσει έτσι κι. Καλύτερο ανά κάτι ως. Παραδώσεις αν που. Αρπάζεις ροή αλγόριθμου μέρος ίδιο αναγκάζονται.', 'Κάνεις γεγονός σπίτι εφαρμογής. Εργαζόμενοι βγήκε χρονοδιαγράμματα σε δε εκτός.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('44', '0802581734', '0404550381');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('44', '128241', '2022-07-28 00:00:00', '2022-09-03 00:00:00', 'Αποθηκευτικού μέρος δημιουργια γέλασαν διαφήμιση εκδόσεις συγχωνευτεί. Αποδείξεις εκτός ρωτάει βιβλίο δύο. Εκτός κάνε ύψος ποια μέρος ξέχασε ναι εκθέσεις.', 'Στήλες έξι πρώτο τον γράψει των.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('45', '1301429404', '0910538676');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('45', '29332', '2020-05-11 00:00:00', '2020-06-26 00:00:00', 'Συνάδελφος σχεδιαστής ήδη στη φράση. Πήρε εγώ διάσημα. Της τρόπο δε κλπ θα.
