INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('46', '118598', '2021-05-14 00:00:00', '2021-06-23 00:00:00', 'Απομόνωση το έστελνε όταν πολύ πάρεις μέρος. Περιβάλλον τις χειρότερα αντιλήφθηκαν.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('47', '1209810216', '2205416852');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('47', '108745', '2022-11-17 00:00:00', '2022-12-27 00:00:00', 'Προγραμματιστές πετούν τα διαδίκτυο που βασανίζουν. Βγήκε θα λίγο.', 'Όσο δημιουργείς νέο διορθώσει τη που συγγραφής.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('48', '1109428284', '1501975395');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('48', '78651', '2020-10-06 00:00:00', '2020-12-02 00:00:00', 'Ήδη κάτι εκτελέσεις ρωτάει λιγότερο ποια. Παραδοτέου ήδη χρόνου για τεκμηριώνει εντολές. Έτσι στις σημαντικός ευκολότερο επεξεργασία σαν ανώδυνη.', 'Θα μετρήσεις γραφικά να δε μη γνωρίζουμε.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('49', '1207427571', '2208825367');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('49', '27473', '2023-07-18 00:00:00', '2023-07-27 00:00:00', 'Ύψος μέχρι ορίστε εφαρμογή αφήσεις. Θέματα δυστυχής έξι βουτήξουν του άλγεβρα. Πες εγώ εφαμοργής δυστυχώς κρατάει προσθέσει.
