INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('50', '18700', '2020-06-17 00:00:00', '2020-07-17 00:00:00', 'Τρέξει κάτι πάντα προγραμματιστές και μέσης. Διάβασε πρώτοι ένας κόψεις σε σου επενδυτής. Νέο σου λοιπόν τους μιας από ύψος εκδόσεις.', 'Μας παράδειγμα για ίδιο. Ίδιο κειμένων δημιουργήσεις ταξινομεί αντιλήφθηκαν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('51', '2111532740', '1206681535');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('51', '64961', '2026-09-03 00:00:00', '2026-10-31 00:00:00', 'Πάρα εκείνου το έστειλε προκαλείς λέει. Μπορούσες και γράψει γιαυτό. Ποια δε δοκιμάσεις μάλλον. Υψηλότερη συνάδελφος πρώτοι πάντως πλέον βρίσκονται έτσι κύκλο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('52', '2911689167', '1504113652');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('52', '84998', '2024-04-24 00:00:00', '2024-06-10 00:00:00', 'Εκτελείται παραδοτέου ανώδυνη. Έξι συνέχεια γράψει μια φαινόμενο νόμιζες.
