INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('54', '3110765587', '1805971952');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('54', '75124', '2021-09-20 00:00:00', '2021-10-11 00:00:00', 'Εκτελέσεις μα σχεδιαστής. Κειμένων ρωτήσει λέει πακέτων να κάτι. Επενδυτής αρέσει παίρνουν να ημέρα απαράδεκτη στη.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('55', '1007513743', '0112988267');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('55', '43886', '2025-11-09 00:00:00', '2025-12-23 00:00:00', 'Τεκμηριώνει πετούν νέων νέα μέρος έξι δίνοντας. Διασφαλίζεται τη επεξεργασία προβληματική.', 'Βασανίζουν βάζοντας χρησιμοποιούσες γνωστή συνεχώς μια.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('56', '0708733889', '0208406055');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('56', '41975', '2023-04-28 00:00:00', '2023-05-28 00:00:00', 'Πάντως του άρα κάτι περιβάλλοντος ότι όσο. Τον αν χαμηλός τον στα ανώδυνη συγχωνευτεί πιο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('57', '1803800903', '0305058496');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('57', '114364', '2020-01-12 00:00:00', '2020-03-10 00:00:00', 'Συγχωνευτεί εγώ ιδιαίτερα ύψος. Ορίστε δύο προσλάμβανες έστειλε αποδείξεις.', 'Εργασίας ας κανένας κώδικα. Διορθώσει δύο βιβλίο έτσι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('58', '1402646365', '0510087485');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('58', '120352', '2021-10-29 00:00:00', '2021-12-08 00:00:00', 'Το πιο ευκολότερο εδώ συνάδελφος αντιλήφθηκαν εγώ. Πολύ διευθυντές σημαντικό ειδικά εκθέσεις πεδία. Όχι σκεφτείς απαράδεκτη ένας πάντως ροή ήδη.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('59', '2111532740', '1403725141');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('59', '37665', '2022-09-24 00:00:00', '2022-11-02 00:00:00', 'Τους προσθέσει γιαυτό πλέον. Ένα προγραμματιστής προβληματική όχι απαρατήρητο. Ποια το επιδιόρθωση ποια στις προγραμματιστές αλγόριθμου.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('60', '2607905982', '0405769536');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('60', '36148', '2023-09-07 00:00:00', '2023-09-16 00:00:00', 'Ότι ας κρατήσουν εκείνου πόρτες αλγόριθμου χαρτιού. Χρονοδιαγράμματος χρησιμοποιούσες προσλάμβανες. Επιδιόρθωση πιο όταν περίπου.', 'Διευθυντές εκδόσεις αλγόριθμου πολύ κλπ κλπ.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('61', '2411004971', '2206580644');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('61', '1590', '2020-03-07 00:00:00', '2020-04-23 00:00:00', 'Υψηλότερη μας εδώ έτοιμος. Διολισθήσεις κανείς αποστηθίσει αρέσει.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('62', '3110765587', '0807776513');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('62', '20156', '2022-05-20 00:00:00', '2022-06-09 00:00:00', 'Μαγικά ταξινομεί εξοργιστικά βιβλίο χρονοδιαγράμματος πλέον. Υπηρεσία παραδοτέου τύπους τη λίγο ιδιαίτερα δεδομένων. Τις πλέον ως πες εντολές στις.', 'Έξι ειδικά επιδιορθώσεις εφαρμογή.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('63', '0410862119', '1711219538');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('63', '126455', '2026-06-26 00:00:00', '2026-07-19 00:00:00', 'Προβληματική όταν στέλνοντάς ότι βάζοντας και. Συνηθίζουν διασφαλίζεται χαρακτηριστικό πες παραδοτέου προσπαθήσεις προϊόντα. Ποια γραμμές μέγιστη νόμιζες.', 'Διευθυντές σε εδώ ήδη φαινόμενο κρατάει. Διακοπής φίλος κώδικάς ώρα επί.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('64', '2205469029', '2404429599');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('64', '152701', '2024-03-02 00:00:00', '2024-03-23 00:00:00', 'Διαχειριστής διοικητικό λοιπόν. Προσλάμβανες χρόνου μέχρι περισσότερη.', 'Πες χαρακτηριστικό εκτελέσει περιβάλλον κειμένων ότι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('65', '0708733889', '2210197258');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('65', '140707', '2020-12-16 00:00:00', '2021-01-09 00:00:00', 'Συνεχώς ξέχασε τον συγκεντρωμένοι μέσης κανένας εξακολουθεί νέων. Γνωστή επί πάντα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('66', '2911689167', '2205416852');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('66', '72282', '2026-09-01 00:00:00', '2026-10-18 00:00:00', 'Να προβληματική ελέγχου. Μέσης νέα στο έχω τρέξει έγραψες.', 'Τρόποι γεύματος την τον ένα πλέον πλέον.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('67', '2003609278', '2201087342');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('67', '21883', '2021-10-02 00:00:00', '2021-10-19 00:00:00', 'Να αποστηθίσει πάρα το ήδη ιδιαίτερα ερωτήσεις. Εξοργιστικά μας έτσι πλέον τρέξει κειμένων αποφάσισε χρησιμοποιώντας. Κάτι τύπους της διαχειριστής.', 'Ότι αθόρυβες συνεχώς έξι θα αυτός νέο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('68', '1009974497', '0307502774');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('68', '61131', '2025-02-26 00:00:00', '2025-04-10 00:00:00', 'Κάτι συνέχεια πιο πλέον ένας διορθώσεις ο. Εργασίας ωραίο έστελνε τις θα συνέχεια απόλαυσε. Απαρατήρητο φαινόμενο μέχρι μέχρι.', 'Πάντως βαθμό όσο σωστά. Διορθώσει δημιουργείς πετάνε σημεία γραμμές αν επί.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('69', '3012870045', '0806014938');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('69', '83336', '2025-04-28 00:00:00', '2025-06-04 00:00:00', 'Γέλασαν των αναφορά μη τέλειοι ατόμου όταν. Συγγραφής εργαζόμενοι δυστυχής νιρβάνα. Τις εργάστηκε λαμβάνουν μα το γραμμή όταν εξαρτάται.', 'Μεταφραστής στα χάος εδώ έχω.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('70', '2502902231', '1004967910');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('70', '120557', '2023-12-12 00:00:00', '2023-12-31 00:00:00', 'Πρώτης σταματάς δείξει. Σταματάς καταλάθος δύο τέλειοι στραβά.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('71', '1108642138', '2112406558');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('71', '106017', '2026-01-02 00:00:00', '2026-01-31 00:00:00', 'Επί αφήσεις αναφορά και το. Πολύ πάρα σημαντικός έλεγχος διακοπής έτσι. Είχαμε των στήλες στις δεν ναι σημαντικός.', 'Παραγωγικής τα εξακολουθεί διάβασε κοιτάζοντας. Δύο συνηθίζουν κάτι δημιουργια.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('72', '2910956816', '2310039586');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('72', '10010', '2020-04-26 00:00:00', '2020-06-19 00:00:00', 'Περισσότερες ένας ως της περισσότερες. Βιβλίο μέχρι εκτός εσωτερικών προβληματική δυστυχώς διαδίκτυο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('73', '2801801564', '0311233042');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('73', '115980', '2026-04-02 00:00:00', '2026-04-18 00:00:00', 'Ίδιο μα διάβασε διαχειριστής. Νέα τύπου δε άρα πάντα. Υψηλότερη κανείς ερωτήσεις απομόνωση αποθηκευτικού. Ατόμου κι θα βιβλίο προκύπτουν κώδικα γέλασαν.', 'Έλεγχος και κι ρωτάει μην διάσημα. Απόλαυσε δεν κανείς επί έχω εξακολουθεί.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('74', '1209483269', '0803099805');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('74', '146307', '2020-05-24 00:00:00', '2020-05-31 00:00:00', 'Συνηθίζουν τέλειοι βγήκε συγχρόνως χαρακτηριστικών τη εφαμοργής δύο. Έχω κι κόψεις επεξεργασία έχω.', 'Προσοχή επενδυτής προσθέσει ποια κάνε. Εκτός λίγο του.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('75', '0103962870', '2206580644');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('75', '122719', '2026-03-09 00:00:00', '2026-03-25 00:00:00', 'Θέλεις περίπου εγώ πιο. Αποθηκευτικού λιγότερο πιο. Εργαζόμενων όταν θέμα ειδικά.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('76', '2911689167', '1810694252');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('76', '88040', '2024-02-17 00:00:00', '2024-03-07 00:00:00', 'Και διοικητικό διαφήμιση εκτελείται θέλεις προσπαθούν. Εργάστηκε χρονοδιαγράμματα ξέχασε για όχι.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('77', '2502902231', '2110925240');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('77', '6802', '2026-03-07 00:00:00', '2026-03-11 00:00:00', 'Συνάδελφος ήδη νιρβάνα υπηρεσία. Προσπαθούν αγοράζοντας προϊόντα μπορούσες φράση εκτελέσει. Σαν φαινόμενο ας τρόπο προσπαθούν αναγκάζονται.', 'Συγγραφείς τη πάντα ακούσει μέχρι παίξουν πακέτων ένας.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('78', '3012509660', '1701197374');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('78', '62890', '2023-06-06 00:00:00', '2023-07-27 00:00:00', 'Επιστρέφουν μετρήσεις πετάξαμε πάντα. Την ημέρα νέου τι. Πεδία κοιτάζοντας χρησιμοποιούνταν τον σας απαρατήρητο τους.', 'Δημιουργείς πολύ βιαστικά σου ίδιο. Κύκλο έτσι εργασίας εξαρτάται σταματάς ο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('79', '2306446564', '2707918946');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('79', '5127', '2024-05-17 00:00:00', '2024-07-15 00:00:00', 'Γιαυτό ωραίο τρόπο μάλλον διάβασε βιαστικά. Για αλγόριθμου από παράγοντες.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('80', '1009974497', '3001785948');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('80', '128268', '2025-12-14 00:00:00', '2026-01-09 00:00:00', 'Δεν σπίτι τι χαμηλός πάντα σημεία ποια. Και ποσοστό πολύ συγκεντρωμένοι πες στα εγώ. Διαπιστώνεις χαμηλός εγώ κι την σημαντικός σίγουρος.', 'Γεγονός παραδοτέου στη τις την εξοργιστικά πλέον λιγότερο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('81', '2905541171', '0304796784');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('81', '59990', '2024-04-21 00:00:00', '2024-06-16 00:00:00', 'Γνωστή πήρε νόμιζες εκτός ανταγωνιστής άρα μετράει.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('82', '2906540192', '3001785948');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('82', '109178', '2020-08-12 00:00:00', '2020-08-16 00:00:00', 'Μάλλον παράδειγμα εκτός μας ακούσει. Ανά θέματα φράση μου.', 'Διαπιστώνεις ως τα πολύ.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('83', '2106602456', '0905149025');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('83', '121530', '2023-05-21 00:00:00', '2023-07-10 00:00:00', 'Επί κι πάντα όσο όταν σας μετρήσεις αυτήν. Έρθει αποθηκευτικού κόλπα νέου τον στο.
