INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('84', '51935', '2022-04-15 00:00:00', '2022-06-09 00:00:00', 'Θέματα πρόσληψη χρονοδιαγράμματα εσωτερικών όσο ανά πάντως. Τα εκθέσεις μην γνωστή από. Εικόνες χρησιμοποιώντας κρατήσουν πεδία χρησιμοποιούνταν.', 'Στήλες σας εξαρτάται πεδία. Εκτελείται ήδη προσπαθήσεις τον μετράει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('85', '0202939499', '2004552385');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('85', '28171', '2023-07-05 00:00:00', '2023-07-17 00:00:00', 'Συνέχεια ρουτίνα δοκιμάσεις της πλέον όχι. Και στήλες σωστά σταματάς απίστευτα μέρος.', 'Ποια σχεδιαστής ας ανά πάντως εκείνου με.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('86', '0404978442', '1108228734');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('86', '75354', '2022-10-16 00:00:00', '2022-11-03 00:00:00', 'Ένας αποστηθίσει αγοράζοντας εργαζόμενων συνάδελφος πολύ. Κανείς πάντα υψηλότερη δυστυχώς λετπά. Βιβλίο και δύο τρέξει κρατάει.', 'Όταν καλύτερο προβληματική. Πάντως συγγραφείς εξαρτάται ιδιαίτερα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('87', '0706543302', '1709409251');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('87', '7954', '2021-10-20 00:00:00', '2021-12-01 00:00:00', 'Αγοράζοντας πάρεις έχω χρησιμοποιώντας. Όταν εκτελείται έχω αποστηθίσει επιδιορθώσεις.', 'Πάντως χώρου ανταγωνιστής μου συνηθίζουν ωραίο δουλεύει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('88', '2910956816', '0307502774');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('88', '52665', '2024-01-15 00:00:00', '2024-03-14 00:00:00', 'Τα ειδικά πολύ στις. Ο διασφαλίζεται εκθέσεις μάθε πάντως πλέον μια. Πως αγοράζοντας υψηλότερη επιδιόρθωση αν συγχωνευτεί νιρβάνα.
