INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('89', '77556', '2023-09-14 00:00:00', '2023-11-06 00:00:00', 'Διαδίκτυο απαρατήρητο βάζοντας τις πλέον ιδιαίτερα. Προσεκτικά πλέον ας. Αν δωροδοκηθούν σαν τα όχι. Εταιρείες πετάξαμε όταν επί δημιουργια.', 'Εκτελείται ανταγωνιστής προγραμματιστής τις κάνε ένα.');
