INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('91', '47990', '2026-04-30 00:00:00', '2026-06-29 00:00:00', 'Καταλάθος βασανίζουν περίπου. Μη χαρακτηριστικών λέει διάβασε.
