INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('92', '42309', '2024-07-12 00:00:00', '2024-08-11 00:00:00', 'Πιο σημαντικό πετάξαμε διακοπής χαρτιού δε ρωτάει. Δε σίγουρος άρα στο πως φίλος. Τελειώσει σας άρα ανακλύψεις ανακλύψεις. Κάτι βιαστικά κάνεις των.', 'Επεξεργασία φακέλους πολύ επιδιορθώσεις. Χρησιμοποίησέ είχαμε πιο και.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('93', '0103962870', '1211580926');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('93', '139307', '2020-03-20 00:00:00', '2020-04-10 00:00:00', 'Πρόσληψη περίπου στα ερωτήσεις. Μη τεσσαρών με δούλευε έτσι εκτελείται. Σας πιο στα χειρότερα τι.', 'Υπηρεσία κειμένων παραπάνω αν γέλασαν. Αναγκάζονται μαγικά βιβλίο να.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('94', '1009974497', '2201087342');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('94', '137965', '2021-06-30 00:00:00', '2021-07-14 00:00:00', 'Ειδικά γεύματος πάντως ανταγωνιστής κοιτάζοντας τρέξει βασανίζουν. Μεταφραστής δοκιμάσεις δεν δούλευε αφήσεις απόλαυσε υόρκη. Θα επεξεργασία κώδικάς προσοχή φακέλους.', 'Δημιουργείς δωροδοκηθούν από για βασανίζουν ρωτήσει πεδία.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('95', '2404738380', '0803099805');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('95', '69969', '2021-09-22 00:00:00', '2021-11-06 00:00:00', 'Έχω δυστυχής ερώτηση αντιλήφθηκαν αρχεία. Ανταγωνιστής προκαλείς ταξινομεί σημαντικό θυμάμαι. Γεύματος ειδικά χρησιμοποιώντας. Κάτι υψηλότερη χρόνου μη παίρνει.', 'Πετάνε στραβά βγήκε τα εργάστηκε ναι. Ο κάτι μεταφραστής.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('96', '2411651898', '2004552385');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('96', '105380', '2024-05-31 00:00:00', '2024-06-25 00:00:00', 'Για μερικούς αναφορά περίπου έλεγχος σημαντικός αρέσει. Κάτι ο αναφορά δύο μη.
