INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('97', '72420', '2026-03-14 00:00:00', '2026-03-29 00:00:00', 'Ίδιο χαρακτηριστικών δυστυχώς πόρτες. Δεδομένων νέου το συγγραφείς θέλεις πρώτο. Πλέον μην πάρα σου υποψήφιο μας. Πάντως λετπά ερώτηση ακούσει μα.', 'Πως εσωτερικών αν υόρκη. Μαγικά και τελειώσει τρόπο.');
