INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('108', '1207427571', '2507538617');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('108', '46629', '2020-04-18 00:00:00', '2020-06-06 00:00:00', 'Ιδιαίτερα ανά χαμηλός χρονοδιαγράμματα εδώ προβληματική μεταγλωτιστής εκτός. Πήρε κόψεις γεύματος στήλες σπίτι ανακλύψεις βιβλίο εδώ.', 'Πηγαίου μην στη μετράει συνεχώς διολισθήσεις. Ας συνεχώς περιβάλλοντος σου στη.');
