INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('113', '25757', '2022-06-20 00:00:00', '2022-07-16 00:00:00', 'Νιρβάνα νέα μου τα δείξει εργάστηκε. Περιβάλλον οι δεν ατόμου αποφάσισε. Λέει μέγιστη ανταγωνιστής της. Έστειλε τις εφαρμογής ποια τέλειοι.', 'Ακούσει διαχειριστής δείξει οι επιστρέφουν. Έξι μας διακοπή για ναι τις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('114', '1908663047', '0608947743');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('114', '140133', '2024-12-07 00:00:00', '2024-12-12 00:00:00', 'Συγκεντρωμένοι καταλάθος ακούσει διασφαλίζεται αναφορά άρθρων λετπά απίστευτα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('115', '1209810216', '2203183514');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('115', '126256', '2023-08-15 00:00:00', '2023-08-23 00:00:00', 'Χαμηλός συνηθίζουν σταματάς τι συνηθίζουν. Επί σημαντικό μεταγλωτίσει ένας εδώ συνεντεύξεις.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('116', '2801897549', '0403843997');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('116', '66510', '2023-07-02 00:00:00', '2023-07-29 00:00:00', 'Για εργοστασίου προσπαθήσεις τοπικές προβληματική. Μας αποκλειστικούς το μέχρι μαγικά σκεφτείς.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('117', '2305692753', '2808413232');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('117', '18584', '2024-06-07 00:00:00', '2024-06-19 00:00:00', 'Όταν μάθε αντιλήφθηκαν πλέον μα από έχω. Εκτελείται τις εργάστηκε επενδυτής γραμμές.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('118', '3012509660', '0906744291');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('118', '39745', '2020-09-14 00:00:00', '2020-09-28 00:00:00', 'Με τα διακόψουμε απαράδεκτη εσωτερικών ρωτήσει παραπάνω. Ιδιαίτερα μέσης επιδιόρθωση απαράδεκτη. Ροή πετούν άρα τύπους περιβάλλοντος βγήκε μπορούσες.', 'Τρόπο κώδικα πάντα βιαστικά. Μιας γραμμές ανά περίπου σημεία εφαμοργής.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('119', '1007513743', '0405769536');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('119', '100967', '2020-06-11 00:00:00', '2020-07-18 00:00:00', 'Ελέγχου βαθμό επί. Στις άρθρων έξι μιας διαφήμιση μέσης.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('120', '2411651898', '1603558833');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('120', '43895', '2026-10-01 00:00:00', '2026-10-09 00:00:00', 'Έστειλε ανά τα απαραίτητο θέματα. Εδώ και μέχρι πολύ προσπαθούν λετπά. Μας συνηθίζουν απαράδεκτη την μέγιστη προκαλείς παράδειγμα. Δύο παράγοντες ήδη πάρεις.', 'Σημαντικό ο μέσης παραγωγικής πάντως κειμένων.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('121', '2106602456', '2304451401');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('121', '85599', '2025-04-29 00:00:00', '2025-05-01 00:00:00', 'Στα πως επιδιόρθωση τύπους ας θέμα εσωτερικών. Βιβλίο ο εξοργιστικά την σε για. Στο συνέχεια βιαστικά καταλάθος.', 'Χαρακτηριστικό δούλευε πήρε μιας άρα στις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('122', '2404738380', '2806407108');
