INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('124', '2305692753', '1805971952');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('124', '3738', '2025-09-07 00:00:00', '2025-09-26 00:00:00', 'Προσοχή έλεγχος κανένας μη. Συγγραφείς πολύ μετρήσεις που υπηρεσία χρησιμοποιούνταν όταν έξι. Κάτι εκτελέσει οι στήλες μας κώδικάς.', 'Φίλος που μέσης άρθρων. Στο πετάξαμε προσοχή πρώτοι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('125', '1009974497', '0608947743');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('125', '100345', '2023-11-11 00:00:00', '2023-12-28 00:00:00', 'Αναφορά νέα αλγόριθμου να εφαμοργής επί πηγαίου. Για στο αλγόριθμου μάτσο.
