INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('127', '1712008709', '1009096688');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('127', '9446', '2021-10-18 00:00:00', '2021-11-01 00:00:00', 'Μπορούσες ταξινομεί αντιλήφθηκαν τη πρώτοι ας. Πρώτο δυστυχώς κύκλο πάντα απομόνωση ρωτάει σε. Σημαντικό μηχανής πετάνε χρειάζονται σε κρατήσουν εργάστηκε.', 'Στο διαδίκτυο τελειώσει. Στις το θα σημαντικός.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('128', '2305692753', '1907030712');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('128', '149387', '2021-02-07 00:00:00', '2021-04-05 00:00:00', 'Διακόψουμε φαινόμενο κάτι ρουτίνα μην εδώ. Εκτός τι μου. Πάντα θυμάμαι ταξινομεί παίρνει απαραίτητο περισσότερες τα.', 'Το πλέον εντολές σίγουρος βιαστικά σημαντικός εκτελέσει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('129', '0312964109', '1211580926');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('129', '146840', '2026-11-13 00:00:00', '2026-12-13 00:00:00', 'Συνέχεια φίλος στα. Διοικητικό συνηθίζουν για σας βρίσκονται. Κι θέμα ας σου στα.', 'Όχι αφήσεις στις. Τρόποι διορθώσεις δείξει εξαρτάται έρθει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('130', '3012509660', '1011068644');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('130', '104388', '2021-02-26 00:00:00', '2021-03-22 00:00:00', 'Δύο μάτσο μέρος αντιλήφθηκαν. Πολύ από ότι αφήσεις στις ναι του. Λοιπόν όχι κάτι. Οι προσπαθούν ήδη σταματάς.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('131', '2906540192', '1612414904');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('131', '62746', '2025-05-05 00:00:00', '2025-06-02 00:00:00', 'Πρόσληψη κάτι κανείς του πεδία. Σου γραμμή άρα ερωτήσεις χώρου. Αποδείξεις διάβασε διαχειριστής στήλες.', 'Χρησιμοποιούνταν θέμα λετπά γράψει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('132', '2003609278', '2202794381');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('132', '139933', '2020-07-09 00:00:00', '2020-07-17 00:00:00', 'Που σκεφτείς δεν τους δημιουργήσεις και. Προκαλείς τη κλπ κώδικα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('133', '1008990170', '1603797884');
