INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('136', '25498', '2020-02-17 00:00:00', '2020-03-04 00:00:00', 'Τεσσαρών διάβασε κανένας θυμάμαι πάντως πολύ εργαζόμενων. Ανταγωνιστής τεκμηριώνει μαγικά κανένας μεταφραστής μάλλον διευθυντές κοιτάζοντας.', 'Ερωτήσεις εφαρμογή παραγωγικής συγγραφείς.');
