INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('137', '2906', '2024-12-07 00:00:00', '2024-12-27 00:00:00', 'Σπίτι τεκμηριώνει κλπ χρησιμοποιούσες φράση.
