INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('138', '77067', '2022-05-15 00:00:00', '2022-06-08 00:00:00', 'Μηχανής πρώτο ωραίο έξι ρωτήσει διακοπή αναφέρονται. Ως βάζοντας χώρου βρίσκονται. Στα κι ένα μέχρι για.', 'Κόψεις μετράει σαν ατόμου.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('139', '2501995986', '0305415843');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('139', '77270', '2022-11-29 00:00:00', '2022-12-15 00:00:00', 'Διολισθήσεις προκαλείς γιαυτό εκτός. Πάρεις πετάνε διορθώσει μέρος. Διορθώσεις εικόνες δύο τι προσθέσει ύψος μια.', 'Τελειώσει νέα λέει όσο οι πως. Κώδικα επί ανά σημαντικός νέα τη πρόσληψη.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('140', '2305633067', '0606763202');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('140', '108653', '2022-10-03 00:00:00', '2022-11-07 00:00:00', 'Ένας κάτι τελειώσει. Μετρήσεις απόλαυσε ήδη ήδη λιγότερο. Διαχειριστής πιο σωστά μέχρι στραβά. Λίγο σε έχω τεσσαρών άρα.', 'Αλγόριθμου διαπιστώνεις στραβά ναι νέου.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('141', '1209810216', '3108126244');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('141', '134077', '2023-09-23 00:00:00', '2023-09-30 00:00:00', 'Σας εδώ χαρακτηριστικό τύπου προκύπτουν. Σταματάς έτσι χρονοδιαγράμματος τεσσαρών πιο χάος. Θέματα υόρκη τύπους εκτελέσει ένα παραπάνω.', 'Ώρα πως σου. Περιβάλλοντος επί μην δεν χρόνου.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('142', '1109428284', '0310707817');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('142', '158953', '2025-10-14 00:00:00', '2025-11-24 00:00:00', 'Ένα πες ας χαμηλός ερωτήσεις χρονοδιαγράμματος. Εργαλείων ποια ο σπίτι εργαλείων προγραμματιστές. Έρθει δύο το ανταγωνιστής σχεδιαστής δεν τέλειοι.', 'Διολισθήσεις πως πιο δημιουργήσεις δημιουργείς προσπαθούν εξαρτάται.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('143', '2402877693', '2307877811');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('143', '79207', '2025-08-08 00:00:00', '2025-08-13 00:00:00', 'Ζητήσεις εγώ ρωτήσει κανόνα λίγο ο κειμένων απόλαυσε. Κάνεις διάβασε γέλασαν ύψος αποδείξεις κόψεις ειδικά.', 'Κόψεις μη ως επεξεργασία πάρεις. Έχω σαν ταξινομεί περισσότερη.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('144', '2906627360', '1701197374');
