INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('148', '1810910652', '0511416310');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('148', '37380', '2022-03-22 00:00:00', '2022-04-02 00:00:00', 'Φίλος κάτι γεύματος οι εντολές κώδικα βιαστικά. Διαδίκτυο ως εκτελείται εικόνες και ερώτηση επιδιόρθωση. Λέει απαράδεκτη ευκολότερο. Χρονοδιαγράμματος στο φράση.', 'Ημέρα τα μην μετράει. Έτσι προσοχή ναι κάτι φίλος οι.');
