INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('152', '0706543302', '0411706871');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('152', '159966', '2023-12-06 00:00:00', '2023-12-30 00:00:00', 'Είχαμε τελειώσει νέων πες αν πάρεις σημεία της. Πως περιμένουν την τη. Πρώτης ανά σου χρονοδιαγράμματα διορθώσεις απλό κρατάει.', 'Παράδειγμα με διορθώσεις. Ένα προγραμματιστές ιδιαίτερα κάνεις λίγο.');
