INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('156', '1301442380', '0310669006');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('156', '53002', '2020-04-24 00:00:00', '2020-05-13 00:00:00', 'Είχαμε απόλαυσε ιδιαίτερα ένας παραπάνω τέλειοι. Έγραψες κύκλο θυμάμαι περίπου νέα τύπους. Εξαρτάται δύο ρουτίνα προσθέσει εργαλείων καλύτερο διάσημα.', 'Δείξει την τους εργαλείων προγραμματιστές. Εκτελείται νέων με μια μιας από.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('157', '2801801564', '0809715419');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('157', '73685', '2025-09-17 00:00:00', '2025-10-20 00:00:00', 'Τρέξει εργασίας δείξει έτσι δούλευε. Παραδώσεις ποια ρωτήσει αφήσεις. Στη τρέξει βιαστικά θέματα.', 'Διασφαλίζεται σε δοκιμάσεις μια όχι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('158', '2305692753', '2310039586');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('158', '121825', '2025-12-17 00:00:00', '2026-02-14 00:00:00', 'Κοιτάζοντας μην κάνεις διάσημα συγχρόνως.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('159', '2710919774', '0901435907');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('159', '147355', '2020-11-23 00:00:00', '2020-12-18 00:00:00', 'Δύο γειτονιάς ήδη είχαμε ναι την χειρότερα δεν. Για διορθώσεις πως. Εργάστηκε γνωστή γραφικά θέλεις με βάζοντας ήδη με.', 'Έχω ρωτάει γραμμές μια ότι. Γεγονός από νιρβάνα μπορούσες αποθηκευτικού.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('160', '1007513743', '0102948147');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('160', '123219', '2023-07-20 00:00:00', '2023-08-26 00:00:00', 'Αγοράζοντας με μετράει μέχρι μέχρι ιδιαίτερα βουτήξουν. Μέχρι παράγοντες λοιπόν κόψεις τις εντολές επί. Αποδείξεις τρέξει σταματάς προκύπτουν. Γεγονός πετάξαμε ας ανά χρόνου του.', 'Λέει εργαζόμενων σημαντικό γειτονιάς ίδιο δεν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('161', '1611621504', '1010459322');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('161', '105265', '2020-12-10 00:00:00', '2021-01-24 00:00:00', 'Μπουν εγώ παραδοτέου ότι. Διορθώσει με το πολύ επί συνεντεύξεις λετπά.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('162', '1007513743', '0309603964');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('162', '17265', '2025-12-08 00:00:00', '2025-12-26 00:00:00', 'Πάρεις χρονοδιαγράμματα επί συγκεντρωμένοι που των μα. Αποφάσισε είχαμε στραβά κόψεις σαν σίγουρος φαινόμενο πεδία. Γέλασαν μαγικά χρονοδιαγράμματα που.', 'Μάτσο έτοιμος έστελνε εξαρτάται κοιτάζοντας δύο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('163', '2809979050', '0411712547');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('163', '101175', '2020-09-09 00:00:00', '2020-10-16 00:00:00', 'Να περιβάλλον βιβλίο άρθρων νόμιζες άλγεβρα. Χαρακτηριστικών πολύ δουλεύει προσοχή επιδιορθώσεις δημιουργείς εξαρτάται. Σπίτι χρησιμοποιούνταν νόμιζες προγραμματιστές άλγεβρα νέου.', 'Ένα επιχείριση τους αποφάσισε δωροδοκηθούν πλέον σαν. Δε ας επί.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('164', '3012509660', '1001214930');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('164', '42190', '2022-04-08 00:00:00', '2022-06-05 00:00:00', 'Εργοστασίου ίδιο τους ατόμου. Πακέτων εκδόσεις τις ήδη μέχρι ένας μαγικά. Ερωτήσεις εδώ στη αυτός. Διαφήμιση κι στο της.', 'Ροή γεγονός έχω χάος. Πολύ εγώ ευκολότερο βγήκε τεκμηριώνει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('165', '2708580170', '0401524365');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('165', '38141', '2022-08-30 00:00:00', '2022-10-08 00:00:00', 'Είχαμε κι κρατήσουν ώρα δύο τρέξει διακόψουμε αποστηθίσει. Ατόμου να μετρήσεις τύπους διορθώσει θέλεις πιο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('166', '0701944806', '1508692893');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('166', '14640', '2025-09-15 00:00:00', '2025-11-03 00:00:00', 'Στα σημαντικό οι εξαρτάται. Μη χαμηλός δίνοντας απλό. Ίδιο ορίστε ανταγωνιστής συγχωνευτεί.', 'Πλέον ας ήδη έξι σπίτι διαπιστώνεις σημαντικός.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('167', '0404978442', '1606886766');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('167', '120301', '2023-04-05 00:00:00', '2023-05-13 00:00:00', 'Πόρτες πάντα μα τι πάντα αποδείξεις. Έτσι μια στη. Τεκμηριώνει ώρα στις καλύτερο εκτός θυμάμαι ανταγωνιστής χειρότερα.', 'Ύψος συνάδελφος μπορούσες υπηρεσία μαγικά θέλεις. Πάρα άρα διορθώσει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('168', '2708580170', '2907676995');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('168', '155941', '2023-04-29 00:00:00', '2023-06-13 00:00:00', 'Κάτι μετράει χρειάζονται έστελνε. Σπίτι έτοιμος μάτσο βρίσκονται διαχειριστής ερώτηση. Τέλειοι έστειλε χώρου δημιουργήσεις αναφορά.', 'Πετάνε συγγραφής αρπάζεις προκύπτουν σαν χειρότερα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('169', '1112753348', '1701840753');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('169', '81002', '2020-04-05 00:00:00', '2020-04-19 00:00:00', 'Φακέλους νόμιζες παραδοτέου αγοράζοντας πάντως εγώ μας.', 'Και τρόπο άλγεβρα χαρακτηριστικό φαινόμενο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('170', '1502550745', '1906627394');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('170', '29082', '2020-05-16 00:00:00', '2020-06-01 00:00:00', 'Απαρατήρητο ρουτίνα πετούν φίλος διακόψουμε μην μέχρι αν. Στα δημιουργείς άρθρων μεταγλωτιστής υόρκη αρέσει αφήσεις.', 'Ελέγχου δεν έστελνε γεύματος σημαντικός εγώ μερικούς.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('171', '2911689167', '1007750457');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('171', '31138', '2023-12-17 00:00:00', '2024-02-09 00:00:00', 'Νέων κρατήσουν φίλος μεταφραστής πρόσληψη ρωτήσει. Επιστρέφουν σημεία εξοργιστικά εδώ προϊόντα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('172', '3012870045', '2205416852');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('172', '74982', '2024-05-02 00:00:00', '2024-05-26 00:00:00', 'Σας σου έρθει μάλλον. Διαπιστώνεις έχω τον απομόνωση.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('173', '2911689167', '2609838048');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('173', '158377', '2022-07-06 00:00:00', '2022-08-08 00:00:00', 'Υπηρεσία αφήσεις νιρβάνα διαχειριστής είχαμε είχαμε. Έρθει δεν ας στη έτσι ίδιο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('174', '1912455789', '1906627394');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('174', '63888', '2025-10-03 00:00:00', '2025-11-16 00:00:00', 'Τέλειοι κάτι επιχείριση στήλες. Τη στις εφαρμογής. Πρόσληψη αποκλειστικούς εικόνες ότι κοιτάζοντας πετάξαμε. Διαδίκτυο πολύ βασανίζουν είχαμε εσωτερικών ήδη ύψος εφαμοργής.', 'Νέα μάθε πηγαίου ημέρα. Τις γέλασαν σας επιδιόρθωση ένας ειδικά.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('175', '0305579221', '0606763202');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('175', '145692', '2022-12-03 00:00:00', '2023-01-02 00:00:00', 'Άπειρα εκτός εφαρμογής προβληματική γέλασαν αθόρυβες. Κάτι εργοστασίου γραμμής πήρε να. Σημεία κώδικάς πετάνε ένα μου διασφαλίζεται ας.', 'Στη της κι επί επί χρησιμοποιούνταν σαν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('176', '2203591874', '0906867705');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('176', '110426', '2026-03-03 00:00:00', '2026-03-17 00:00:00', 'Άρα δείξει του προσπαθήσεις. Τι κλπ ημέρα γραφικά. Εφαρμογή άρα της πες βάζοντας ροή.', 'Τρέξει άρθρων δωροδοκηθούν αλγόριθμου δημιουργια νόμιζες.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('177', '2003609278', '2901588087');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('177', '111200', '2021-07-26 00:00:00', '2021-08-26 00:00:00', 'Διορθώσει γέλασαν κειμένων αποφάσισε. Διάσημα υπηρεσία επιδιόρθωση εικόνες παραπάνω.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('178', '0402587115', '1004967910');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('178', '135967', '2026-04-07 00:00:00', '2026-04-25 00:00:00', 'Προσεκτικά αρχεία εξακολουθεί έτσι τον.', 'Τη σταματάς ιδιαίτερα μου. Πως εργοστασίου άπειρα έτσι άρα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('179', '1810910652', '0210050553');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('179', '46294', '2026-07-18 00:00:00', '2026-08-14 00:00:00', 'Ποια συγκεντρωμένοι στα μιας ωραίο. Μέχρι εδώ εφαμοργής εκτός ανακλύψεις. Σωστά διολισθήσεις προσπαθούν οι ένα ποια όταν.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('180', '0405994014', '3105867267');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('180', '115150', '2022-03-17 00:00:00', '2022-04-28 00:00:00', 'Παραδοτέου τον εργασίας επί συγγραφής. Βρίσκονται θέμα γιαυτό επιστρέφουν εργοστασίου εργαλείων τις. Ας μα αποδείξεις το.', 'Εταιρείες πάρεις πρόσληψη μέσης απαρατήρητο της εγώ.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('181', '1810910652', '1508692893');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('181', '159969', '2025-07-04 00:00:00', '2025-08-21 00:00:00', 'Την να τελειώσει σημαντικό τη διαδίκτυο αν. Ανά κι και απαρατήρητο μια. Κι κύκλο προσπαθούν ατόμου όχι πάντα.', 'Πάντα πακέτων νόμιζες θέματα. Απαρατήρητο πλέον των κάνεις μας μαγικά.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('182', '2411004971', '2609838048');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('182', '39444', '2024-08-05 00:00:00', '2024-09-21 00:00:00', 'Μεταφραστής παίρνουν βαθμό πιο τι τελειώσει. Τον σημαντικός ανά κώδικα ορίστε στη συνάδελφος.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('183', '0701944806', '2911618637');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('183', '4613', '2025-06-27 00:00:00', '2025-08-02 00:00:00', 'Μεταγλωτιστής εργαλείων συνεχώς συνάδελφος περιμένουν βασανίζουν ένα. Ευκολότερο οι εγώ όχι πετούν κι.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('184', '0902609962', '1208436584');
