INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('185', '150884', '2026-02-12 00:00:00', '2026-02-26 00:00:00', 'Θέμα τη έτσι. Στη τον και διασφαλίζεται πάρα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('186', '2404738380', '0608947743');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('186', '89762', '2025-08-29 00:00:00', '2025-10-01 00:00:00', 'Όσο απαράδεκτη ατόμου ήδη μετράει είχαμε κάτι. Διακόψουμε μάθε τοπικές επενδυτής. Παράγοντες τι διαφήμιση δούλευε.', 'Περιβάλλοντος σημεία εικόνες θα αποκλειστικούς έλεγχος.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('187', '2406419109', '1909077893');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('187', '36558', '2025-07-08 00:00:00', '2025-07-17 00:00:00', 'Πετάνε ας ειδικά. Επί τρόπο ως σας περιβάλλοντος επιστρέφουν χρησιμοποιώντας. Κι αποδείξεις γνωστή μέχρι ναι.', 'Διορθώσει δύο μεταγλωτίσει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('188', '0404978442', '1311938597');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('188', '5123', '2020-01-19 00:00:00', '2020-01-23 00:00:00', 'Επιδιορθώσεις δυστυχής λαμβάνουν μέρος. Βουτήξουν ότι από δυστυχώς.', 'Παραδοτέου συνεντεύξεις εικόνες γέλασαν δύο από νέο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('189', '1808559940', '1504489594');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('189', '110564', '2021-06-16 00:00:00', '2021-07-30 00:00:00', 'Πρώτης εταιρείες βιβλίο. Ήδη κι τρόποι ανεπιθύμητη τις άρα ίδιο. Έξι τεσσαρών ακούσει θυμάμαι ροή επί μια.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('190', '2502902231', '1711219538');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('190', '43859', '2020-10-27 00:00:00', '2020-10-31 00:00:00', 'Διορθώσει δημιουργια σαν.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('191', '3012598800', '2802258035');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('191', '106578', '2022-02-17 00:00:00', '2022-03-19 00:00:00', 'Στο αποκλειστικούς ξέχασε πλέον. Πάντως δίνοντας ανταγωνιστής ρωτάει. Δυστυχώς γραμμή δε χρησιμοποιούσες όσο τι.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('192', '0707820743', '0809715419');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('192', '132924', '2021-08-03 00:00:00', '2021-08-22 00:00:00', 'Κύκλο στήλες επί προσπαθούν κανένας ο. Μπουν στα βαθμό ας μηχανής.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('193', '2205469029', '1701197374');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('193', '134648', '2024-07-29 00:00:00', '2024-08-14 00:00:00', 'Έχω εργαζόμενοι να έξι διαχειριστής τι. Δυστυχώς εκτελείται μια το εξακολουθεί εικόνες.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('194', '1705602559', '0407492098');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('194', '85530', '2023-08-02 00:00:00', '2023-08-17 00:00:00', 'Και μας σου παραπάνω χρονοδιαγράμματος.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('195', '0307549248', '0510660375');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('195', '139995', '2023-02-20 00:00:00', '2023-03-01 00:00:00', 'Δεν αποθηκευτικού εκθέσεις. Σου χρησιμοποιώντας βασανίζουν μια κάνε μετράει γεγονός γεγονός.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('196', '2205469029', '1101655806');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('196', '64630', '2025-08-16 00:00:00', '2025-08-17 00:00:00', 'Κι περιβάλλον δημιουργείς περιεχόμενα. Αντιλήφθηκαν ανά τα κλπ χρονοδιαγράμματος πάντως τις. Έχω που όταν κλπ.', 'Κανένας υψηλότερη πάντως μέσης αρέσει μερικούς. Μεταφραστής τρόποι όταν νέων.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('197', '1108642138', '1909077893');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('197', '91083', '2026-02-22 00:00:00', '2026-04-06 00:00:00', 'Περισσότερη μα ποσοστό μέχρι. Διακοπή των επεξεργασία εκτός με σπίτι υψηλότερη σίγουρος. Βιαστικά λέει πρώτης στα.', 'Ότι μέχρι λέει εκτελέσει δωροδοκηθούν πιο έτσι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('198', '2203591874', '1609775336');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('198', '12332', '2026-02-26 00:00:00', '2026-04-08 00:00:00', 'Κειμένων νέων υόρκη εκτελέσεις κανόνα συγκεντρωμένοι όταν. Να γεγονός δύο. Αθόρυβες των μαγικά κόψεις ήδη αυτός μιας.', 'Ανακλύψεις νιρβάνα προϊόντα νέου παραδώσεις. Που μαγικά στα νόμιζες νέα θέμα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('199', '1109428284', '3105047062');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('199', '68050', '2024-10-26 00:00:00', '2024-11-12 00:00:00', 'Κειμένων κι μην σου. Χρονοδιαγράμματος έλεγχος κανόνα χάος ναι. Εκτελέσεις προκαλείς δωροδοκηθούν δε.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('200', '0306542190', '0304226385');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('200', '91279', '2022-03-12 00:00:00', '2022-04-05 00:00:00', 'Το το τρόποι τρόποι ζητήσεις από έστελνε σπίτι. Ένα παραδώσεις περιεχόμενα αποθηκευτικού άρθρων και ύψος.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('201', '2205469029', '3001785948');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('201', '30351', '2026-06-02 00:00:00', '2026-06-09 00:00:00', 'Συνάδελφος από πολύ αποστηθίσει του στραβά. Συνεχώς απόλαυσε μια. Περισσότερη έξι εργαλείων χρησιμοποιώντας.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('202', '2906627360', '2201087342');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('202', '106043', '2021-06-24 00:00:00', '2021-08-22 00:00:00', 'Του διολισθήσεις μη σίγουρος προσπαθούν μου. Λέει στέλνοντάς χαρτιού και επιστρέφουν. Διακόψουμε κώδικάς άτομο θυμάμαι.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('203', '2404738380', '1804013485');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('203', '143020', '2020-12-16 00:00:00', '2021-02-01 00:00:00', 'Παραδώσεις όχι που εργαζόμενοι εκτός. Δεν νιρβάνα προκαλείς εργαζόμενων άρα κι σημεία ιδιαίτερα. Δείξει κοιτάζοντας τρόπο φαινόμενο περισσότερη εγώ.', 'Στη μπουν πολύ ας στη ένα πρώτης. Ειδικά μου βρίσκονται εξαρτάται κάνε.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('204', '0906651672', '0808960014');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('204', '61767', '2020-04-14 00:00:00', '2020-05-15 00:00:00', 'Ορίστε ένας τοπικές σου βουτήξουν αποθηκευτικού. Με πήρε νέων συγγραφείς ένας. Έξι εκτελέσει λιγότερο.', 'Όχι εξαρτάται αυτήν πλέον στις πετάξαμε περιμένουν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('205', '2801801564', '1609775336');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('205', '29544', '2020-04-14 00:00:00', '2020-04-19 00:00:00', 'Περιβάλλον μεταφραστής και ήδη μα στα. Εντολές τέλειοι ρωτήσει μέχρι. Κανείς ανακλύψεις χρονοδιαγράμματα εδώ αντιλήφθηκαν αρέσει κάτι.', 'Κρατάει δυστυχώς απλό. Εταιρείες έτοιμος εγώ.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('206', '0111689660', '2101054987');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('206', '103922', '2020-07-24 00:00:00', '2020-09-14 00:00:00', 'Μετράει δεδομένων το ρωτάει. Ποσοστό χρονοδιαγράμματος κάνεις συγγραφής. Δωροδοκηθούν νόμιζες αντιλήφθηκαν ήδη άρα γνωστή.', 'Των προβληματική διαφήμιση κάνε δε. Τη έξι στο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('207', '1207427571', '0809715419');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('207', '21016', '2023-12-01 00:00:00', '2024-01-14 00:00:00', 'Δυστυχής εφαρμογή ο. Νόμιζες ρωτάει το χρησιμοποιούνταν εδώ εγώ.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('208', '2501995986', '1102770382');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('208', '119735', '2025-02-22 00:00:00', '2025-04-05 00:00:00', 'Ας δεν και σωστά χρησιμοποιούσες. Ημέρα αν μέχρι έτσι ποια σωστά ταξινομεί.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('209', '2906540192', '1709409251');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('209', '133137', '2021-06-21 00:00:00', '2021-07-08 00:00:00', 'Περισσότερη μεταγλωτιστής περιβάλλον συγγραφείς ως εξακολουθεί δίνοντας. Απαρατήρητο πήρε βαθμό συνεχώς συνεντεύξεις σου από.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('210', '0708733889', '0605510600');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('210', '111833', '2020-08-18 00:00:00', '2020-09-17 00:00:00', 'Ώρα εκτός σπίτι μιας συγχωνευτεί. Γεύματος εκτός σαν ανταγωνιστής. Πως πιο προσλάμβανες σίγουρος εκτελέσει ρωτάει του παραπάνω.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('211', '1705602559', '2306891683');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('211', '86115', '2024-02-16 00:00:00', '2024-03-09 00:00:00', 'Μεταγλωτιστής πάντως φράση. Τα αθόρυβες λέει ανά από. Χρησιμοποιώντας ακούσει τα συνεντεύξεις.', 'Στις εδώ μας παράγοντες. Σας ξέχασε γραμμής άρα συνεχώς τις εκτός.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('212', '2106602456', '0902442730');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('212', '155946', '2020-03-04 00:00:00', '2020-03-13 00:00:00', 'Μη τοπικές έξι εργαλείων κλπ. Πετάνε εταιρείες ζητήσεις βασανίζουν. Ναι έτσι πλέον επί δημιουργείς.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('213', '2311474214', '1411689363');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('213', '53226', '2026-09-17 00:00:00', '2026-09-26 00:00:00', 'Πως μαγικά εδώ σας πηγαίου. Πιο διάβασε κοιτάζοντας σταματάς προϊόντα. Τοπικές βιαστικά βουτήξουν. Ρωτήσει μπορούσες ίδιο εγώ ένα προγραμματιστής ανά.', 'Από γραμμές αναφορά χρησιμοποίησέ αρπάζεις. Εργασίας μα δεν ταξινομεί ροή.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('214', '2411651898', '1410207364');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('214', '50802', '2023-03-17 00:00:00', '2023-05-04 00:00:00', 'Εκθέσεις έλεγχος δύο συνεντεύξεις ότι. Γνωρίζουμε και μην εδώ παίρνουν. Έξι επενδυτής τις επιστρέφουν περιεχόμενα αναγκάζονται με σπίτι.', 'Ποσοστό ερωτήσεις κάτι έγραψες τον. Εκθέσεις ίδιο νέου τρόπο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('215', '1912455789', '1211580926');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('215', '35039', '2021-07-06 00:00:00', '2021-07-09 00:00:00', 'Μέγιστη γνωστή συνάδελφος τοπικές συνέχεια τεσσαρών λετπά.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('216', '1803800903', '0903954105');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('216', '133839', '2023-07-28 00:00:00', '2023-08-29 00:00:00', 'Κόψεις λοιπόν δημιουργήσεις τα. Έτσι διαφήμιση ρωτήσει να του έτσι. Ίδιο απαρατήρητο διαδίκτυο διασφαλίζεται παράδειγμα ρουτίνα.', 'Αποθηκευτικού πετούν που. Εργαλείων πάντως κύκλο με τα καταλάθος.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('217', '0103962870', '1211580926');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('217', '99445', '2021-09-19 00:00:00', '2021-10-08 00:00:00', 'Έγραψες χρησιμοποιούνταν πιο όσο μεταγλωτίσει από. Δυστυχώς αναγκάζονται πάντως εκτός. Σπίτι σταματάς την μα.', 'Χαρακτηριστικό τη όχι σκεφτείς διαπιστώνεις πάντα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('218', '0701944806', '0407072044');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('218', '77900', '2026-05-02 00:00:00', '2026-06-08 00:00:00', 'Εργαζόμενοι να ήδη τους εφαρμογή στη επενδυτής ήδη. Καταλάθος ανακλύψεις λετπά ατόμου. Επιστρέφουν στα θέλεις γραμμής πακέτων απαρατήρητο προγραμματιστής.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('219', '1008990170', '0112988267');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('219', '88174', '2021-08-01 00:00:00', '2021-09-02 00:00:00', 'Μα συγχρόνως στη διαφήμιση. Συγχωνευτεί ίδιο με ανεπιθύμητη.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('220', '2311474214', '1101655806');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('220', '149845', '2023-03-18 00:00:00', '2023-05-10 00:00:00', 'Αποστηθίσει με που δύο. Αναγκάζονται συνεντεύξεις τις προγραμματιστές άρα κειμένων δωροδοκηθούν. Άλγεβρα ημέρα μεταφραστής πολύ ρωτάει των τον.', 'Σε τη τι έρθει γειτονιάς από σου.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('221', '1908663047', '1603797884');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('221', '161289', '2021-08-24 00:00:00', '2021-09-13 00:00:00', 'Εξακολουθεί εκείνου σε κάτι. Προσοχή ανταγωνιστής επιχείριση συνεντεύξεις τους.', 'Εταιρείες πάντα λίγο ναι. Άρθρων σκεφτείς αναφέρονται.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('222', '0706543302', '1606886766');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('222', '129117', '2025-06-21 00:00:00', '2025-07-25 00:00:00', 'Συνάδελφος στις διάσημα χρονοδιαγράμματος ότι παραδώσεις έτσι.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('223', '2111532740', '1004967910');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('223', '121493', '2025-08-08 00:00:00', '2025-09-02 00:00:00', 'Σχεδιαστής λιγότερο κι που κανένας στραβά φαινόμενο. Τέλειοι επί περισσότερες. Λίγο αναφέρονται λιγότερο εργασίας.', 'Διορθώσει χρόνου έχω αλγόριθμου πετάνε.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('224', '2809979050', '2206580644');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('224', '69494', '2020-05-15 00:00:00', '2020-05-20 00:00:00', 'Διαχειριστής δοκιμάσεις περισσότερες το διαδίκτυο απλό. Διοικητικό περιεχόμενα παίξουν πετούν. Διοικητικό πρόσληψη σας λίγο έξι ώρα εκείνου ένα. Θέμα διαχειριστής του μη.', 'Πολύ πρόσληψη διαδίκτυο έτοιμος ανά εργαζόμενοι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('225', '1109428284', '2407167798');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('225', '83840', '2023-08-20 00:00:00', '2023-08-31 00:00:00', 'Αθόρυβες τρόπο μια τους μιας. Λετπά μου εφαρμογή αρέσει στη κειμένων. Παίρνουν εσωτερικών εργαζόμενοι μεταγλωτιστής εργοστασίου πρώτο ιδιαίτερα.', 'Διάσημα ρωτήσει διορθώσεις πόρτες μέρος κόλπα μηχανής. Αν όσο προσοχή όχι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('226', '0402587115', '2904000839');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('226', '29302', '2026-04-30 00:00:00', '2026-05-09 00:00:00', 'Των προσοχή κοιτάζοντας χρησιμοποιώντας. Στήλες καταλάθος ανεπιθύμητη ανά οι χρησιμοποιούνταν σημαντικός σημεία.', 'Επί μιας πετούν κάτι. Μάτσο όχι εργαζόμενων κειμένων κειμένων δεν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('227', '2502902231', '1603558833');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('227', '123880', '2021-01-14 00:00:00', '2021-01-30 00:00:00', 'Τον διακοπής εφαρμογής επιδιόρθωση λίγο συνεχώς εδώ ίδιο. Βασανίζουν κάτι γιαυτό έχω προϊόντα σκεφτείς έχω τις. Εκτός μην πάντως πάρεις λέει στη για λέει.', 'Βασανίζουν χαρακτηριστικό εκτός μεταγλωτιστής τα στη από.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('228', '1112753348', '2004552385');
