INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('229', '110504', '2023-08-21 00:00:00', '2023-09-12 00:00:00', 'Σημαντικός σπίτι αθόρυβες ημέρα λοιπόν άρα κρατήσουν. Ναι εδώ ο χρόνου μας.
