INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('231', '100536', '2025-06-13 00:00:00', '2025-08-12 00:00:00', 'Επί προϊόντα άτομο ναι πρώτοι. Ανακλύψεις ειδικά φράση ελέγχου εκτελείται.', 'Γεγονός παράγοντες κλπ όχι επιδιόρθωση σημαντικός κόλπα.');
