INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('233', '1209483269', '2410806416');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('233', '79256', '2022-06-23 00:00:00', '2022-07-25 00:00:00', 'Πετάξαμε αγοράζοντας δεν κι διακοπή. Διάβασε προβληματική σαν πάντα νέου στη βασανίζουν ροή. Ναι εφαρμογής πόρτες στραβά τρέξει μετρήσεις.', 'Δυστυχής λίγο δημιουργήσεις εδώ κειμένων εντολές.');
