INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('235', '1808559940', '2211498362');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('235', '150647', '2020-06-22 00:00:00', '2020-08-05 00:00:00', 'Κανείς που νέων κώδικάς. Ευκολότερο στέλνοντάς ξέχασε πρόσληψη δημιουργείς τρόπο ακούσει. Τι ποια περιβάλλοντος ως χρησιμοποιούνταν γιαυτό.', 'Συγχωνευτεί ανακλύψεις πετούν εκείνου έγραψες. Έξι τελειώσει δεν δούλευε.');
