INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('238', '116854', '2022-09-06 00:00:00', '2022-10-12 00:00:00', 'Αναγκάζονται δε πάντως πακέτων διάσημα πιο οι. Προσοχή εκδόσεις ανώδυνη ειδικά εργαλείων μεταγλωτίσει που δεν.', 'Μεταφραστής παίξουν τι κανείς μετράει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('239', '2906540192', '0510087485');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('239', '111001', '2021-03-15 00:00:00', '2021-05-03 00:00:00', 'Μάθε τη διευθυντές μερικούς μέχρι σημαντικό περιβάλλοντος ερώτηση. Ανά συνεντεύξεις χρησιμοποιούσες εκδόσεις.', 'Υποψήφιο τύπου έχω προϊόντα. Έλεγχος τοπικές νέα μα παραδώσεις όταν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('240', '2906540192', '1508692893');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('240', '130463', '2021-10-17 00:00:00', '2021-12-02 00:00:00', 'Δείξει σημαντικό χάος ροή. Άλγεβρα συνέχεια πρώτης δούλευε περιβάλλοντος συνηθίζουν τελειώσει. Γεγονός δεν όχι κανείς και νέων.', 'Ξέχασε από έτσι μεταγλωτίσει πάντα δυστυχώς εφαρμογή μέγιστη.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('241', '2106602456', '2307877811');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('241', '71477', '2026-09-26 00:00:00', '2026-11-12 00:00:00', 'Ελέγχου παραγωγικής φράση αυτός. Δωροδοκηθούν μέχρι δημιουργήσεις μάθε απλό.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('242', '2111532740', '1602028026');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('242', '14824', '2024-02-29 00:00:00', '2024-03-23 00:00:00', 'Βουτήξουν χρησιμοποιούνταν τύπου νέων έξι βαθμό τρέξει. Εργαλείων νέο περισσότερες βρίσκονται σημαντικός γιαυτό.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('243', '0405403482', '0407492098');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('243', '115054', '2025-03-22 00:00:00', '2025-04-27 00:00:00', 'Ότι επιχείριση το απόλαυσε αυτός συγκεντρωμένοι έστειλε. Μιας δημιουργήσεις τι αποδείξεις.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('244', '1712008709', '1701840753');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('244', '121987', '2022-06-25 00:00:00', '2022-08-19 00:00:00', 'Ποια σπίτι γειτονιάς πλέον. Συνάδελφος γραμμή διάσημα ήδη εργοστασίου.', 'Ρωτήσει φράση εντολές εξαρτάται κοιτάζοντας.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('245', '1007513743', '0706448500');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('245', '53365', '2022-07-30 00:00:00', '2022-08-16 00:00:00', 'Ατόμου εξακολουθεί θα κάτι οι. Κάτι διαδίκτυο προσπαθήσεις συγγραφής. Τις προσπαθήσεις μέχρι ημέρα πετούν. Κώδικα διακόψουμε επεξεργασία δυστυχώς πρώτοι ροή εκτός.', 'Όταν τις ήδη μου προκύπτουν πρώτο θυμάμαι. Συγκεντρωμένοι φακέλους αρπάζεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('246', '2404738380', '2211498362');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('246', '102108', '2026-10-03 00:00:00', '2026-12-02 00:00:00', 'Απαραίτητο συγγραφής τις βάζοντας μου γιαυτό προσεκτικά δοκιμάσεις. Νέα σχεδιαστής διαφήμιση πολύ διοικητικό.', 'Θέλεις σταματάς χρονοδιαγράμματος.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('247', '0103962870', '0909990472');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('247', '159278', '2021-04-23 00:00:00', '2021-05-17 00:00:00', 'Πες διάβασε μη χρονοδιαγράμματα τοπικές υψηλότερη περιβάλλοντος τις. Ταξινομεί τύπου έχω πρόσληψη. Άρα σας έξι για.', 'Αναφέρονται ανά ανταγωνιστής.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('248', '2203591874', '0311233042');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('248', '157575', '2024-01-10 00:00:00', '2024-02-27 00:00:00', 'Αρέσει εγώ μερικούς. Κόλπα σου τους χαμηλός αποθηκευτικού. Διακόψουμε ένας δοκιμάσεις χρονοδιαγράμματος ήδη εκτός.', 'Εκτός ρωτάει εργάστηκε νέου λιγότερο σας δε.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('249', '2502902231', '1701894379');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('249', '120539', '2023-05-01 00:00:00', '2023-05-04 00:00:00', 'Συνέχεια ένα όταν αποθηκευτικού περίπου.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('250', '1402646365', '1002683337');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('250', '132270', '2024-01-20 00:00:00', '2024-03-16 00:00:00', 'Καταλάθος την χαρτιού εκτελέσεις δεν. Παίρνουν μια ίδιο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('251', '2203591874', '2901588087');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('251', '66075', '2020-07-12 00:00:00', '2020-08-01 00:00:00', 'Οι διορθώσει τις δεν διαδίκτυο. Προσεκτικά ναι εικόνες τους προβληματική στις.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('252', '1009974497', '0106175216');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('252', '160845', '2024-01-15 00:00:00', '2024-02-13 00:00:00', 'Χρονοδιαγράμματος δημιουργήσεις εκθέσεις κάνε τρέξει εξαρτάται σωστά πρώτης. Θα ίδιο έτσι μερικούς δούλευε.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('253', '1402646365', '0510481986');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('253', '136838', '2020-01-20 00:00:00', '2020-02-16 00:00:00', 'Σίγουρος δυστυχώς τεκμηριώνει χαρτιού διάβασε θέμα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('254', '2411004971', '1612755043');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('254', '62454', '2024-08-14 00:00:00', '2024-08-16 00:00:00', 'Φράση χρησιμοποιούσες χώρου στο βρίσκονται εντολές γνωστή. Εκτός χρησιμοποιούσες βαθμό έτσι γέλασαν.', 'Μέχρι στη κοιτάζοντας έξι. Έτσι πεδία σε ίδιο συγχρόνως διακοπή ξέχασε κρατάει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('255', '2411651898', '2112540086');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('255', '46190', '2023-02-24 00:00:00', '2023-04-06 00:00:00', 'Διακοπή της πλέον πήρε.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('256', '0807736496', '0204156229');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('256', '155922', '2020-05-22 00:00:00', '2020-06-18 00:00:00', 'Ορίστε διαπιστώνεις γιαυτό μέσης κανείς προσπαθούν. Ύψος ως ναι ιδιαίτερα καταλάθος αποθηκευτικού αποστηθίσει. Στραβά παράγοντες συνέχεια προγραμματιστές προγραμματιστές πες.', 'Κάτι εφαμοργής το ωραίο εξοργιστικά πιο φίλος για. Γεύματος δύο σε.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('257', '3108788705', '1207555071');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('257', '1099', '2020-01-07 00:00:00', '2020-01-18 00:00:00', 'Από σας εικόνες μέγιστη συνεντεύξεις κανένας. Χρησιμοποιώντας έχω στο εκθέσεις εφαμοργής βάζοντας.', 'Προσεκτικά διάσημα νέα σε συγκεντρωμένοι στη μα μα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('258', '2910450715', '0310669006');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('258', '110480', '2020-05-12 00:00:00', '2020-06-11 00:00:00', 'Αποδείξεις τις του κάτι πιο άλγεβρα. Όχι γραμμής πιο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('259', '1502550745', '3105055034');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('259', '104367', '2026-05-06 00:00:00', '2026-05-28 00:00:00', 'Μερικούς περιμένουν ανακλύψεις. Στήλες συγκεντρωμένοι ναι θέματα συγχρόνως κάτι.', 'Πάρα λετπά ημέρα υποψήφιο μη χάος το.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('260', '1008990170', '0809149671');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('260', '102804', '2024-02-18 00:00:00', '2024-02-25 00:00:00', 'Χρησιμοποίησέ από ποια διακόψουμε ας. Γνωστή προκαλείς τα έξι τρόποι. Κρατήσουν χαρτιού θέλεις αποκλειστικούς.', 'Ένα πες ότι απαράδεκτη τι πάντα σου μέγιστη.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('261', '2411004971', '2206580644');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('261', '52436', '2023-10-03 00:00:00', '2023-11-23 00:00:00', 'Τεσσαρών εργοστασίου αναγκάζονται εδώ. Ακούσει σταματάς αυτήν ότι της. Ανά χρόνου του μιας.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('262', '1502550745', '1701197374');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('262', '135666', '2021-07-29 00:00:00', '2021-08-01 00:00:00', 'Υποψήφιο κρατάει πάντα στραβά. Έχω κάτι πολύ εδώ.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('263', '2910450715', '2410806416');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('263', '107093', '2025-01-01 00:00:00', '2025-01-07 00:00:00', 'Θέλεις αναγκάζονται αφήσεις. Θυμάμαι πολύ σημεία άρα μα χαρακτηριστικό.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('264', '3012598800', '2306891683');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('264', '47540', '2023-11-26 00:00:00', '2023-12-01 00:00:00', 'Εγώ εργάστηκε παραδώσεις κώδικάς τρόποι ένας μηχανής εγώ. Από έστελνε απαράδεκτη.', 'Δυστυχώς από συνεντεύξεις θα. Του για πλέον ζητήσεις. Χώρου διαφήμιση της.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('265', '0807736496', '1005553989');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('265', '115993', '2024-08-10 00:00:00', '2024-09-15 00:00:00', 'Τελειώσει στις διαχειριστής παραδώσεις σου εικόνες να. Σημαντικός και άρα και εκτελέσεις ώρα. Επενδυτής έχω της μηχανής βαθμό γράψει προσπαθούν.', 'Μη συνηθίζουν επιδιορθώσεις περιεχόμενα για μεταγλωτιστής ίδιο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('266', '1008990170', '2901588087');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('266', '137715', '2025-01-13 00:00:00', '2025-02-04 00:00:00', 'Όταν από υψηλότερη δούλευε. Εκείνου θέμα παίξουν θέλεις χρησιμοποιούσες πάντως ευκολότερο αντιλήφθηκαν.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('267', '2305633067', '0211577555');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('267', '78642', '2020-05-08 00:00:00', '2020-05-29 00:00:00', 'Υόρκη σαν προκαλείς ποια μα πάντως. Διαπιστώνεις τα μαγικά βουτήξουν εκτός.', 'Αφήσεις χάος άρα ένα. Έξι στα βαθμό προγραμματιστής διολισθήσεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('268', '2906627360', '1010459322');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('268', '19765', '2026-05-09 00:00:00', '2026-07-02 00:00:00', 'Επεξεργασία ο χρειάζονται πολύ την. Αποδείξεις θα νιρβάνα το.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('269', '2801897549', '0908959952');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('269', '53393', '2021-07-02 00:00:00', '2021-08-21 00:00:00', 'Εργαζόμενοι ερώτηση δυστυχώς δύο βαθμό. Κάτι μεταγλωτιστής απίστευτα προβληματική κάτι μιας άρα.', 'Χαρτιού ποια έχω νιρβάνα στο προσθέσει. Λέει στήλες τύπου. Ώρα απλό εγώ.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('270', '2809979050', '1904918721');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('270', '160178', '2024-08-16 00:00:00', '2024-09-22 00:00:00', 'Έτοιμος δε στο ανώδυνη μέγιστη ωραίο. Δοκιμάσεις ποια δεν γραμμές πρώτοι σου. Τρόποι σου ποσοστό νέων.', 'Μέγιστη σημαντικός αν υψηλότερη και που. Ώρα παίρνουν τη σημαντικός εκτελείται.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('271', '1109428284', '2111074055');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('271', '158728', '2020-09-23 00:00:00', '2020-11-11 00:00:00', 'Έτοιμος βρίσκονται και ας πηγαίου σκεφτείς σε.', 'Έτοιμος κώδικάς αναγκάζονται διαδίκτυο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('272', '0402587115', '3009802250');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('272', '76300', '2024-01-02 00:00:00', '2024-01-22 00:00:00', 'Προσθέσει έξι επιδιορθώσεις. Στο φίλος απαρατήρητο αρχεία τεσσαρών στέλνοντάς δεν. Μην συνεχώς ένα ποια. Ρωτήσει θέματα ροή αν αυτός ας συνεχώς εκείνου.', 'Μάτσο την μάλλον αγοράζοντας ταξινομεί στις. Εδώ πάρα αρπάζεις αναφορά σας.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('273', '3012509660', '2203183514');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('273', '16364', '2020-02-18 00:00:00', '2020-04-07 00:00:00', 'Προσεκτικά χειρότερα δούλευε μερικούς να πάντως σου. Τύπου χρονοδιαγράμματα του. Χάος νέο χαμηλός από.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('274', '2911689167', '1001214930');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('274', '116368', '2026-01-16 00:00:00', '2026-01-28 00:00:00', 'Μετράει ο της παράγοντες διαδίκτυο παράδειγμα συγκεντρωμένοι πάντως. Δημιουργια απόλαυσε όσο κάτι παραγωγικής στις δύο. Άλγεβρα προγραμματιστές έχω.', 'Εργάστηκε πετάξαμε τι γεύματος ζητήσεις θυμάμαι χαμηλός.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('275', '2010494529', '1701894379');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('275', '119607', '2026-06-20 00:00:00', '2026-06-29 00:00:00', 'Βγήκε από μπορούσες μέσης. Αλγόριθμου ταξινομεί χρησιμοποιώντας σαν έξι τι τη εφαμοργής. Τελειώσει επί μα ίδιο στις.', 'Ίδιο ζητήσεις τρόπο τον εργάστηκε.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('276', '0111689660', '0307502774');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('276', '160690', '2026-02-16 00:00:00', '2026-04-07 00:00:00', 'Ιδιαίτερα πρώτοι τις αναφέρονται. Ήδη άπειρα παράδειγμα αντιλήφθηκαν την διάβασε τον επιστρέφουν. Ναι υπηρεσία νέα χρονοδιαγράμματα εκτελέσεις.', 'Μπορούσες ένας αποδείξεις κανόνα νέο ορίστε.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('277', '2609009896', '1010459322');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('277', '126617', '2023-02-14 00:00:00', '2023-04-07 00:00:00', 'Έρθει κάτι πιο χρόνου έρθει. Λαμβάνουν κώδικάς πρόσληψη στη διοικητικό χαρακτηριστικό προβληματική δε. Έστελνε για τοπικές.', 'Γεύματος ένα τις απαράδεκτη απαρατήρητο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('278', '1803800903', '0310669006');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('278', '34477', '2022-03-10 00:00:00', '2022-05-07 00:00:00', 'Ήδη σημαντικό σημεία εκτός προσεκτικά τοπικές.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('279', '0410862119', '0706448500');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('279', '71521', '2022-03-27 00:00:00', '2022-04-04 00:00:00', 'Μιας στα που φαινόμενο μάτσο εκτελέσεις. Μπουν πολύ εργοστασίου εργαζόμενοι παίρνει σχεδιαστής ώρα. Παράγοντες δίνοντας επιστρέφουν κοιτάζοντας να τι ένα εργάστηκε.', 'Έτοιμος εργάστηκε πολύ νόμιζες. Σωστά γράψει νέο του εξοργιστικά.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('280', '3008951757', '1701197374');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('280', '120516', '2024-08-30 00:00:00', '2024-10-01 00:00:00', 'Φακέλους κώδικα προσπαθούν δουλεύει στο. Προβληματική επενδυτής τρόποι νέων μέρος. Προγραμματιστές ένας συνεντεύξεις ιδιαίτερα βαθμό λέει.', 'Λιγότερο αυτήν μπουν παίξουν απομόνωση προσλάμβανες ωραίο.');
